import { serve } from "https://deno.land/std@0.168.0/http/server.ts"
import { createClient } from "https://esm.sh/@supabase/supabase-js@2"

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type, content-encoding',
}

serve(async (req) => {
  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders })

  try {
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL') ?? '',
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
    )

    const contentType = req.headers.get('content-type') || '';
    const contentEncoding = req.headers.get('content-encoding') || '';

    let body;

    // 1. Handle GZIP Compression from Android
    if (contentEncoding.includes('gzip')) {
      const stream = req.body?.pipeThrough(new DecompressionStream("gzip"));
      const text = await new Response(stream).text();
      try {
        body = JSON.parse(text);
      } catch (e) {
        throw new Error(`GZIP Decompression succeeded but JSON parse failed: ${e.message}`);
      }
    } 
    // 2. Handle standard JSON
    else if (contentType.includes('application/json')) {
      body = await req.json();
    } 
    else {
      throw new Error(`Unsupported Content-Type: ${contentType}. Expected application/json or gzip.`);
    }

    const { action, deviceId, payload } = body;
    if (!action || !deviceId) throw new Error("Missing action or deviceId in request payload");

    console.log(`[GATEWAY] Action: ${action} | Device: ${deviceId}`);

    let result, error;

    switch (action) {
      case "upload_stats":
      case "ping":
        ({ data: result, error } = await supabase.from('device_stats').insert({ ...payload, device_id: deviceId }));
        break;
      case "get_commands":
        ({ data: result, error } = await supabase.from('file_commands').select('*').eq('device_id', deviceId).eq('status', 'PENDING'));
        break;
      case "update_command":
        ({ data: result, error } = await supabase.from('file_commands').update({
          status: payload.status, 
          error_log: payload.errorMsg, 
          result_data: payload.resultData, 
          result_file_path: payload.resultFilePath,
          updated_at: new Date().toISOString() 
        }).eq('id', payload.id).eq('device_id', deviceId));
        break;
      case "get_config":
        ({ data: result, error } = await supabase.from('device_config').select('config_json').eq('device_id', deviceId).maybeSingle());
        break;
      case "get_rules":
        ({ data: result, error } = await supabase.from('monitoring_rules').select('*'));
        break;
      case "upload_skeleton":
        ({ data: result, error } = await supabase.from('storage_backups').insert({ ...payload, device_id: deviceId }));
        break;
      case "register_file":
        ({ data: result, error } = await supabase.from('file_registry').insert({ ...payload, device_id: deviceId }));
        break;
      default:
        throw new Error(`Unknown action: ${action}`);
    }

    if (error) throw error;

    return new Response(JSON.stringify({ success: true, data: result }), {
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      status: 200,
    });

  } catch (err) {
    console.error("[GATEWAY_ERROR]", err.message);
    return new Response(JSON.stringify({ success: false, error: err.message }), {
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      status: 500,
    });
  }
})

import { serve } from "https://deno.land/std@0.168.0/http/server.ts"
import { createClient } from "https://esm.sh/@supabase/supabase-js@2"

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
}

serve(async (req) => {
  // Handle CORS
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders })
  }

  try {
    const formData = await req.formData()
    const file = formData.get('file') as File
    const deviceId = formData.get('deviceId') as string
    const category = formData.get('category') as string || 'GENERAL'

    if (!file || !deviceId) {
      return new Response(JSON.stringify({ error: 'Missing file or deviceId' }), { 
        status: 400, headers: { ...corsHeaders, 'Content-Type': 'application/json' } 
      })
    }

    // Initialize Supabase with Service Role Key (Server-side power)
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL') ?? '',
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
    )

    // Sanitize filename and create path: device_id/category/timestamp_name
    const timestamp = Date.now()
    const filePath = `${deviceId}/${category}/${timestamp}_${file.name}`

    // 1. Upload to Storage
    const { data: storageData, error: storageError } = await supabase.storage
      .from('cortex-vault')
      .upload(filePath, file.stream(), {
        contentType: file.type,
        upsert: false
      })

    if (storageError) throw storageError

    // 2. Register in Database
    const { error: dbError } = await supabase
      .from('file_registry')
      .insert({
        device_id: deviceId,
        file_name: file.name,
        file_path: filePath,
        category: category,
        file_size: file.size
      })

    if (dbError) throw dbError

    return new Response(JSON.stringify({ message: 'Upload successful', path: filePath }), {
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      status: 200,
    })

  } catch (error) {
    return new Response(JSON.stringify({ error: error.message }), {
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      status: 500,
    })
  }
})

import { serve } from "https://deno.land/std@0.168.0/http/server.ts"
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2'
import { JWT } from 'https://esm.sh/google-auth-library@9'

serve(async (req) => {
  const now = new Date().toISOString();
  try {
    const payload = await req.json()
    const { record, type } = payload

    console.log(`[${now}] 🚀 Webhook Triggered. Event: ${type}, Command ID: ${record?.id}`);

    if (type !== 'INSERT' || record.status !== 'PENDING') {
      console.log(`[${now}] ⏩ Skipping. Status is ${record?.status}, Type is ${type}`);
      return new Response("Ignore: Not a new pending command", { status: 200 })
    }

    const supabase = createClient(
      Deno.env.get('SUPABASE_URL') ?? '',
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
    )

    console.log(`[${now}] 🔍 Looking for token for Device: ${record.device_id}`);
    const { data: stats, error: dbError } = await supabase
      .from('device_stats')
      .select('fcm_token')
      .eq('device_id', record.device_id)
      .not('fcm_token', 'is', null)
      .order('created_at', { ascending: false })
      .limit(1)

    if (dbError || !stats || stats.length === 0) {
      console.error(`[${now}] ❌ No token found for ${record.device_id}. Data:`, stats, "Error:", dbError);
      return new Response("Device has no registered FCM token", { status: 404 })
    }

    const token = stats[0].fcm_token
    console.log(`[${now}] ✅ Token found. Preparing FCM blast...`);

    const rawServiceAccount = Deno.env.get('FIREBASE_SERVICE_ACCOUNT')
    const serviceAccount = JSON.parse(rawServiceAccount ?? '{}')

    const jwt = new JWT({
      email: serviceAccount.client_email,
      key: serviceAccount.private_key,
      scopes: ['https://www.googleapis.com/auth/cloud-platform'],
    })
    const { token: gToken } = await jwt.getAccessToken()

    console.log(`[${now}] 📡 Sending FCM request to Google...`);
    const fcmResponse = await fetch(
      `https://fcm.googleapis.com/v1/projects/${serviceAccount.project_id}/messages:send`,
      {
        method: 'POST',    
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${gToken}`,
        },
        body: JSON.stringify({
          message: {
            token: token,
            data: { trigger: "new_command", cmd_id: String(record.id) },
            android: { priority: "high" }
          },
        }),
      }
    )

    const result = await fcmResponse.json()
    if (fcmResponse.ok) {
       console.log(`[${now}] 🎯 SUCCESS: Push delivered to Google. Message ID: ${result.name}`);
    } else {
       console.error(`[${now}] 🧨 FCM ERROR:`, result);
    }

    return new Response(JSON.stringify(result), { status: fcmResponse.status })

  } catch (err) {
    console.error(`[${now}] 💀 FATAL CRASH:`, err.message);
    return new Response(err.message, { status: 500 })
  }
})

