2116 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2117 |     function applyLocalPatch(content, ops) {
2118 |         let lines = content.split('\n');
2119 |         let logs = [];
2120 |         let success = true;
2121 | 
2122 |         if (typeof ops === 'string') {
2123 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2124 |         }
2125 | 
2126 |         ops.forEach(op => {
2127 |             if (op.action === 'comment') return;
2128 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2129 |             
2130 |             if (op.action === 'replace_block') {
2131 |                 // Strategy 1: Exact String Match (Fastest)
2132 |                 const currentStr = lines.join('\n');
2133 |                 if (currentStr.includes(op.find_block)) {
2134 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2135 |                     logs.push('Exact match applied');
2136 |                     return;
2137 |                 }
2138 | 
2139 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2140 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2141 |                 if (searchLines.length === 0) return;
2142 | 
2143 |                 let matchStart = -1;
2144 |                 let matchEnd = -1;
2145 | 
2146 |                 // Scan file lines
2147 |                 for (let i = 0; i < lines.length; i++) {
2148 |                     // If first line matches (ignoring whitespace)
2149 |                     if (lines[i].trim() === searchLines[0]) {
2150 |                         // Check subsequent lines
2151 |                         let allMatch = true;
2152 |                         let fileOffset = 0;
2153 |                         let searchOffset = 1;
2154 |                         
2155 |                         while (searchOffset < searchLines.length) {
2156 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2157 |                             const nextFile = lines[i + fileOffset + 1].trim();
2158 |                             // Skip empty lines in file if they aren't in search block
2159 |                             if (nextFile === '') {
2160 |                                 fileOffset++;
2161 |                                 continue;
2162 |                             }
2163 |                             if (nextFile !== searchLines[searchOffset]) {
2164 |                                 allMatch = false;
2165 |                                 break;
2166 |                             }
2167 |                             fileOffset++;
2168 |                             searchOffset++;
2169 |                         }
2170 | 
2171 |                         if (allMatch) {
2172 |                             matchStart = i;
2173 |                             matchEnd = i + fileOffset;
2174 |                             break;
2175 |                         }
2176 |                     }
2177 |                 }
2178 | 
2179 |                 if (matchStart !== -1) {
2180 |                     // Replace the range of lines
2181 |                     const replacement = op.replace_with.split('\n');
2182 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2183 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2184 |                 } else {
2185 |                     success = false;
2186 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2187 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2188 |                 }
2189 |             }
2190 |         });
2191 |         return { content: lines.join('\n'), success, logs };
2192 |     }
