4907 |     // --- GENERIC UI ---
4908 |     function formatBytes(bytes) {
4909 |         if (!bytes) return '0 B';
4910 |         const k = 1024;
4911 |         const sizes = ['B', 'KB', 'MB', 'GB'];
4912 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
4913 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
4914 |     }
