4916 |     function timeAgo(dateString) {
4917 |         const date = new Date(dateString);
4918 |         const now = new Date();
4919 |         const seconds = Math.floor((now - date) / 1000);
4920 |         if (seconds < 10) return 'just now';
4921 |         if (seconds < 60) return seconds + 's ago';
4922 |         const minutes = Math.floor(seconds / 60);
4923 |         if (minutes < 60) return minutes + 'm ago';
4924 |         const hours = Math.floor(minutes / 60);
4925 |         if (hours < 24) return hours + 'h ago';
4926 |         return date.toLocaleDateString();
4927 |     }
