5126 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5127 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5128 |         
5129 |         const navItems = document.querySelectorAll('.nav-item');
5130 |         switchTab(tabId, navItems[navIndex]);
5131 | 
5132 |         const scrollContainer = document.querySelector('.main-view');
5133 |         let retryCount = 0;
5134 |         const MAX_RETRIES = 5;
5135 | 
5136 |         const attemptNavigation = async () => {
5137 |             const element = document.querySelector(selector);
5138 |             
5139 |             if (element) {
5140 |                 console.log("[DeepJump] Element found. Scrolling...");
5141 |                 
5142 |                 // Wait for any tab transition animations
5143 |                 await new Promise(r => setTimeout(r, 300));
5144 | 
5145 |                 let offsetTop = 0;
5146 |                 let curr = element;
5147 |                 while (curr && curr !== scrollContainer) {
5148 |                     offsetTop += curr.offsetTop;
5149 |                     curr = curr.offsetParent;
5150 |                 }
5151 | 
5152 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5153 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5154 | 
5155 |                 // Visual Highlight
5156 |                 element.style.transition = 'all 0.5s ease';
5157 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5158 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5159 |                 setTimeout(() => {
5160 |                     element.style.backgroundColor = '';
5161 |                     element.style.boxShadow = '';
5162 |                 }, 3000);
5163 |                 
5164 |                 console.groupEnd();
5165 |                 return true;
5166 |             }
5167 | 
5168 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5169 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5170 |                 retryCount++;
5171 |                 showGlobalToast("🔍 Searching deeper...");
5172 |                 
5173 |                 await loadMoreFn(); 
5174 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5175 |                 return attemptNavigation();
5176 |             }
5177 | 
5178 |             console.error("[DeepJump] Failed: Element not found after retries.");
5179 |             showGlobalToast("Entry not found in recent history.", true);
5180 |             console.groupEnd();
5181 |             return false;
5182 |         };
5183 | 
5184 |         setTimeout(attemptNavigation, 100);
5185 |     }
