5996 |                         const content = cleanChunk.substring(firstLineEnd + 1);
5997 |                         if (path) pendingImportFiles.push({ path, content });
5998 |                     }
5999 |                 });
6000 |             } 
6001 |             else {
6002 |                 throw new Error("Unsupported file format. Use .zip or .txt exported from Conduit.");
