7284 |     function extractTableNames(sql) {
7285 |         if (!sql) return [];
7286 |         const tables = [];
7287 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7288 |         
7289 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7290 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7291 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7292 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7293 | 
7294 |         let match;
7295 |         while ((match = fromRegex.exec(sql)) !== null) {
7296 |             const name = match[1];
7297 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7298 |                 tables.push(name);
7299 |             }
7300 |         }
7301 |         
7302 |         while ((match = metaRegex.exec(sql)) !== null) {
7303 |             const name = match[1];
7304 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7305 |                 tables.push(name);
7306 |             }
7307 |         }
7308 | 
7309 |         return tables;
7310 |     }
7311 | 
7312 |     function convertToCSV(resultObj) {
7313 |         const data = resultObj.data || [];
7314 |         if (!data.length) return '';
7315 |         
7316 |         const tables = extractTableNames(resultObj.sql);
7317 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7318 | 
7319 |         const headers = Object.keys(data[0]);
7320 |         const rows = data.map(row => 
7321 |             headers.map(header => {
7322 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7323 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7324 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7325 |             }).join(',')
7326 |         );
7327 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7328 |     }
