function editCronJob(job) {
    currentEditingJobId = job.jobid;
    document.getElementById('cron-job-name').value = job.jobname || '';
    document.getElementById('cron-job-name').disabled = true; // Name is usually immutable in pg_cron schedule
    document.getElementById('cron-schedule').value = job.schedule;

    // Extract function slug from command using regex
    const slugMatch = job.command.match(/\/functions\/v1\/([^\/\s']+)/);
    if (slugMatch && slugMatch[1]) {
        const slug = slugMatch[1];
        document.getElementById('cron-target-slug').value = slug;
        // Try to find and activate the pill
        document.querySelectorAll('#cron-fn-selector .filter-pill').forEach(p => {
            p.classList.toggle('active', p.innerText === slug);
        });
    }

    const submitBtn = document.querySelector('#cron-manager-overlay .btn-primary');
    submitBtn.innerHTML = '💾 Update Job';
    submitBtn.style.background = 'var(--ai-accent)';
    submitBtn.style.color = 'white';

    // Scroll to top of overlay
    document.getElementById('cron-manager-overlay').querySelector('div[style*="padding: 20px"]').scrollTop = 0;
    fetchCronJobs(); // Refresh to show highlight
}

